class _NumpySafeEncoder(json.JSONEncoder):
    """JSON encoder that converts numpy types to native Python types.

    Prevents json.dump from crashing on numpy int64/float64 when
    MoviePy clip.duration or other numpy values leak into settings.
    Defined once at module level so slider callbacks in update_setting()
    don't re-create the class on every trigger.
    """
    def default(self, o):
        if isinstance(o, (np.integer,)):
            return int(o)
        if isinstance(o, (np.floating,)):
            return float(o)
        if isinstance(o, (np.ndarray,)):
            return o.tolist()
        if isinstance(o, (np.bool_,)):
            return bool(o)
        return super().default(o)


def _save_settings_atomic(settings, target='overlay_settings.json'):
    """Atomically write a settings dict to a JSON file.

    Uses temp-file-then-rename so a crash or serialization error
    never corrupts the real settings file.  Underscore-prefixed
    keys are filtered out — they are per-render state, not user
    settings.
    """
    _safe = {k: v for k, v in settings.items() if not k.startswith('_')}
    _tmp = target + '.tmp'
    with open(_tmp, 'w', encoding='utf-8') as _f:
        json.dump(_safe, _f, indent=2, ensure_ascii=False,
                  cls=_NumpySafeEncoder)
        _f.flush()
    Path(_tmp).replace(target)
