def get_windows_fonts():
    """Scan Windows fonts folder and return available font family names.

    Uses the Windows Registry to get proper display names (e.g. "Arial Bold"
    instead of "arialbd").  Falls back to combined PIL parsing + stem if the
    registry key is inaccessible, and always injects common fonts plus Urdu
    fonts at the bottom of the list.
    """
    import winreg as _wr
    _FONT_REG_KEY = (
        r"SOFTWARE\Microsoft\Windows NT\CurrentVersion\Fonts"
    )
    _FONT_DIR = Path(r"C:\Windows\Fonts")

    # --- 1. Try the Windows Registry (authoritative display-name→filename) ---
    reg_map: dict[str, tuple[str, str]] = {}  # display_name → (stem, .ttf name)
    try:
        with _wr.OpenKey(_wr.HKEY_LOCAL_MACHINE, _FONT_REG_KEY) as key:
            idx = 0
            while True:
                try:
                    name, value, _ = _wr.EnumValue(key, idx)
                except OSError:
                    break
                idx += 1
                if not isinstance(value, str) or not value.lower().endswith(".ttf"):
                    continue
                # Strip "(TrueType)" / "(OpenType)" suffix from display name
                display = name.rsplit("(", 1)[0].strip()
                ttf_name = Path(value).name  # handle relative paths in value
                stem = Path(value).stem
                reg_map[display] = (stem, ttf_name)
    except Exception:
        reg_map = {}

    # --- 2. Build a stem→display reverse map from registry ---
    stem_to_display: dict[str, str] = {}
    for display, (stem, _) in reg_map.items():
        # Multiple weights of the same family share a stem?  Prefer the longer display name.
        existing = stem_to_display.get(stem)
        if existing is None or len(display) > len(existing):
            stem_to_display[stem] = display

    # --- 3. Scan disk for every .ttf file ---
    display_names: set[str] = set()
    if _FONT_DIR.exists():
        for font_file in _FONT_DIR.glob("*.ttf"):
            stem = font_file.stem
            # Registry lookup first – most reliable
            if stem in stem_to_display:
                display_names.add(stem_to_display[stem])
            else:
                # Attempt PIL to get the readable family name
                try:
                    from PIL import ImageFont
                    font_obj = ImageFont.truetype(str(font_file), 12)
                    # Access the underlying FreeType face's family name
                    family = getattr(font_obj.font, "family", None)
                    style = getattr(font_obj.font, "style", None)
                    if family:
                        name = f"{family} {style}" if style and style != "Regular" else family
                        display_names.add(name)
                        # Also register the reverse mapping so we don't hit PIL again
                        stem_to_display[stem] = name
                    else:
                        display_names.add(stem)
                except Exception:
                    display_names.add(stem)

    # --- 4. Always include common / fallback fonts ---
    ALWAYS_INCLUDE = {
        "Arial", "Arial Bold", "Arial Italic", "Arial Bold Italic",
        "Arial Black",
        "Calibri", "Calibri Bold",
        "Times New Roman", "Times New Roman Bold",
        "Verdana", "Verdana Bold",
        "Impact",
        "Segoe UI", "Segoe UI Bold",
        "Tahoma", "Tahoma Bold",
        "Courier New", "Courier New Bold",
        "Georgia", "Georgia Bold",
        "Comic Sans MS", "Comic Sans MS Bold",
        "Trebuchet MS", "Trebuchet MS Bold",
        # ─── Popular CapCut fonts ─────────────────────────────────
        "Montserrat", "Montserrat Bold",
        "Poppins", "Poppins Bold",
        "Roboto", "Roboto Bold",
        "Bebas Neue",
        "Anton",
        "Oswald", "Oswald Bold",
        "Raleway", "Raleway Bold",
        "Lato", "Lato Bold",
        "Playfair Display", "Playfair Display Bold",
        "DM Sans", "DM Sans Bold",
        "Inter", "Inter Bold",
        "Manrope", "Manrope Bold",
        "Lexend", "Lexend Bold",
        "Space Grotesk", "Space Grotesk Bold",
        "Josefin Sans", "Josefin Sans Bold",
        "Archivo", "Archivo Bold",
        "Cabin", "Cabin Bold",
        "Bangers",
        "Abril Fatface",
        "Franklin Gothic Medium",
        "Gill Sans MT", "Gill Sans MT Bold",
        "Candara", "Candara Bold",
        "Constantia", "Constantia Bold",
        "Corbel", "Corbel Bold",
    }
    display_names.update(ALWAYS_INCLUDE)

    # --- 5. Urdu / Arabic fonts (user-friendly names, may not be installed) ---
    URDU_FONTS = [
        "Arabic Typesetting", "Arabic Typesetting",
        "Arabic Typesetting", "Arabic Typesetting Bold",
        "Arabic Typesetting",
    ]
    display_names.update(URDU_FONTS)

    result = sorted(display_names)

    # Also populate a module-level reverse map so the renderer can find the .ttf file
    global _FONT_FILENAME_MAP
    _FONT_FILENAME_MAP.clear()
    for display, (stem, ttf_name) in reg_map.items():
        _FONT_FILENAME_MAP[display] = ttf_name
    # Fill gaps from stem_to_display for registry-unknown faces
    for display in result:
        if display not in _FONT_FILENAME_MAP:
            for stem, d in stem_to_display.items():
                if d == display:
                    _FONT_FILENAME_MAP[display] = f"{stem}.ttf"
                    break

    return result if result else ["Arial", "Impact", "Verdana", "Arabic Typesetting"]


# Module-level mapping for use by the MoviePy renderer
_FONT_FILENAME_MAP: dict[str, str] = {}


class ModernButton(tk.Button):
    """Custom modern button with hover effects"""
    def __init__(self, parent, **kwargs):
        # Extract custom parameters
        bg_color = kwargs.pop('bg_color', AppStyles.ACCENT_PRIMARY)
        hover_color = kwargs.pop('hover_color', AppStyles.ACCENT_INFO)

        # Set default button styling
        kwargs.setdefault('relief', 'flat')
        kwargs.setdefault('cursor', 'hand2')
        kwargs.setdefault('bg', bg_color)
        kwargs.setdefault('fg', AppStyles.TEXT_WHITE)
        kwargs.setdefault('font', ('Segoe UI', 10, 'bold'))
        kwargs.setdefault('padx', 25)
        kwargs.setdefault('pady', 12)
        kwargs.setdefault('borderwidth', 0)

        super().__init__(parent, **kwargs)

        self.default_bg = bg_color
        self.hover_bg = hover_color

        # Bind hover events
        self.bind('<Enter>', self.on_enter)
        self.bind('<Leave>', self.on_leave)

    def on_enter(self, e):
        self['background'] = self.hover_bg

    def on_leave(self, e):
        self['background'] = self.default_bg


class VideoAutomationGUI(DubbingTabMixin, ThumbnailTabMixin):
    """Main modern GUI application"""

    def __init__(self, root):
        self.root = root
        self.root.title("Video Automation Studio - Professional Edition")
        self.root.geometry("1280x900")  # Larger default size
        self.root.configure(bg=AppStyles.BG_CARD)
        self.root.resizable(True, True)
        self.root.minsize(1100, 800)  # Increased minimum size

        # Make window expand with content
        self.root.grid_rowconfigure(0, weight=1)
        self.root.grid_columnconfigure(0, weight=1)

        # Load settings
        self.settings = self.load_settings()
        self.paths = self.load_paths()
        self.processing = False
        self.process_thread = None

        # Variables for paths
        self.video_folder_var = tk.StringVar(value=self.paths.get('video_folder', ''))
        self.quotes_file_var = tk.StringVar(value=self.paths.get('quotes_file', ''))
        self.output_folder_var = tk.StringVar(value=self.paths.get('output_folder', ''))

        # Progress tracking
        self.progress_var = tk.DoubleVar(value=0)
        self.status_var = tk.StringVar(value="Ready")

        # Enable copy-paste keyboard shortcuts for all text widgets
        self.setup_copy_paste_bindings()

        self.setup_ui()

        # Sync Qwen3 model size at startup
        if qwen3_helper is not None:
            _init_sz = self.settings.get('qwen3_model_size', '0.6B')
            try:
                qwen3_helper.set_model_size(_init_sz)
            except Exception:
                pass

        logger.info("Application started successfully")

    def setup_copy_paste_bindings(self):
        """Setup global copy-paste keyboard shortcuts for all text widgets"""
        # Bind Ctrl+A to select all for Text widgets
        def select_all(event):
            widget = event.widget
            if isinstance(widget, tk.Text):
                widget.tag_add('sel', '1.0', 'end')
                return 'break'
            elif isinstance(widget, tk.Entry):
                widget.select_range(0, tk.END)
                return 'break'
            return None

        # Bind Ctrl+C for copy
        def copy_text(event):
            widget = event.widget
            try:
                if isinstance(widget, tk.Text):
                    if widget.tag_ranges('sel'):
                        text = widget.get('sel.first', 'sel.last')
                        self.root.clipboard_clear()
                        self.root.clipboard_append(text)
                elif isinstance(widget, tk.Entry):
                    if widget.selection_present():
                        text = widget.selection_get()
                        self.root.clipboard_clear()
                        self.root.clipboard_append(text)
            except:
                pass
            return 'break'

        # Bind Ctrl+V for paste
        def paste_text(event):
            widget = event.widget
            try:
                text = self.root.clipboard_get()
                if isinstance(widget, tk.Text):
                    if widget.tag_ranges('sel'):
                        widget.delete('sel.first', 'sel.last')
                    widget.insert('insert', text)
                elif isinstance(widget, tk.Entry):
                    if widget.selection_present():
                        widget.delete('sel.first', 'sel.last')
                    widget.insert('insert', text)
            except:
                pass
            return 'break'

        # Bind Ctrl+X for cut
        def cut_text(event):
            widget = event.widget
            try:
                if isinstance(widget, tk.Text):
                    if widget.tag_ranges('sel'):
                        text = widget.get('sel.first', 'sel.last')
                        self.root.clipboard_clear()
                        self.root.clipboard_append(text)
                        widget.delete('sel.first', 'sel.last')
                elif isinstance(widget, tk.Entry):
                    if widget.selection_present():
                        text = widget.selection_get()
                        self.root.clipboard_clear()
                        self.root.clipboard_append(text)
                        widget.delete('sel.first', 'sel.last')
            except:
                pass
            return 'break'

        # Apply bindings globally
        self.root.bind_class('Text', '<Control-a>', select_all)
        self.root.bind_class('Text', '<Control-A>', select_all)
        self.root.bind_class('Text', '<Control-c>', copy_text)
        self.root.bind_class('Text', '<Control-C>', copy_text)
        self.root.bind_class('Text', '<Control-v>', paste_text)
        self.root.bind_class('Text', '<Control-V>', paste_text)
        self.root.bind_class('Text', '<Control-x>', cut_text)
        self.root.bind_class('Text', '<Control-X>', cut_text)

        # Entry widgets usually work by default, but add explicit bindings
        self.root.bind_class('Entry', '<Control-a>', select_all)
        self.root.bind_class('Entry', '<Control-A>', select_all)

    def load_settings(self):
        """Load settings from JSON file"""
        # Clean up any stale temp files from interrupted saves
        for _stale in Path('.').glob('overlay_settings.json.tmp*'):
            try:
                _stale.unlink()
            except Exception:
                pass
        try:
            settings_file = Path('overlay_settings.json')
            if settings_file.exists():
                with open(settings_file, 'r', encoding='utf-8') as f:
                    return json.load(f)
            else:
                logger.warning("Settings file not found, using defaults")
                return {}
        except Exception as e:
            logger.error(f"Error loading settings: {e}")
            # Backup the corrupted file for manual recovery
            try:
                _backup = Path(f'overlay_settings.json.corrupt.{int(time.time())}')
                Path('overlay_settings.json').rename(_backup)
                logger.warning(f"Backed up corrupt settings to {_backup}")
            except Exception:
                pass
            return {}

    def load_paths(self):
        """Load processing paths from JSON file"""
        try:
            paths_file = Path('processing_paths.json')
            if paths_file.exists():
                with open(paths_file, 'r', encoding='utf-8') as f:
                    return json.load(f)
            else:
                return {}
        except Exception as e:
            logger.error(f"Error loading paths: {e}")
            return {}

    def save_settings(self, show_popup=True):
        """Save settings to JSON file

        Args:
            show_popup: If True, shows success/error popup. If False, saves silently (for auto-save).
        """
        try:
            # Save caption layout and position if they exist
            if hasattr(self, 'caption_layout_var'):
                self.settings['caption_layout'] = self.caption_layout_var.get()
            if hasattr(self, 'caption_position_var'):
                self.settings['caption_position'] = self.caption_position_var.get()
            if hasattr(self, 'caption_preset_var'):
                self.settings['caption_preset'] = self.caption_preset_var.get()

            # Save emoji theme
            if hasattr(self, 'emoji_preset_var'):
                display_value = self.emoji_preset_var.get()
                if hasattr(self, 'emoji_preset_map') and display_value in self.emoji_preset_map:
                    self.settings['emoji_preset_category'] = self.emoji_preset_map[display_value]

            # Save caption font styles
            if hasattr(self, 'caption_font_var'):
                self.settings['caption_font_style'] = self.caption_font_var.get()
            if hasattr(self, 'caption_bg_var'):
                self.settings['caption_bg_enabled'] = bool(self.caption_bg_var.get())
            if hasattr(self, 'caption_highlight_var'):
                self.settings['caption_highlight_enabled'] = bool(self.caption_highlight_var.get())
            if hasattr(self, 'caption_dialogue_var'):
                self.settings['caption_dialogue_enabled'] = bool(self.caption_dialogue_var.get())
            if hasattr(self, 'caption_highlight_font_var'):
                self.settings['caption_highlight_font_style'] = self.caption_highlight_font_var.get()
            if hasattr(self, 'caption_animation_var'):
                self.settings['caption_word_animation'] = self.caption_animation_var.get()
            if hasattr(self, 'gradient_type_var'):
                self.settings['gradient_type'] = self.gradient_type_var.get()

            # Save audio paths
            if hasattr(self, 'bgm_file_var'):
                self.settings['bgm_file'] = self.bgm_file_var.get()
            if hasattr(self, 'vo_path_var'):
                self.settings['voiceover_folder'] = self.vo_path_var.get()
            if hasattr(self, 'voiceover_text_var'):
                self.settings['voiceover_text_file'] = self.voiceover_text_var.get()

            # Save TTS engine preferences (Cloud vs Local Kokoro)
            if hasattr(self, 'tts_engine_var'):
                self.settings['tts_engine'] = self.tts_engine_var.get()
            if hasattr(self, 'kokoro_voice_var'):
                self.settings['kokoro_voice'] = self.kokoro_voice_var.get()
            if hasattr(self, 'kokoro_quality_var'):
                self.settings['kokoro_quality'] = self.kokoro_quality_var.get()

            # Save AI Avatar settings
            if hasattr(self, 'avatar_enabled_var'):
                self.settings['avatar_enabled'] = self.avatar_enabled_var.get()
            if hasattr(self, 'avatar_face_var'):
                self.settings['avatar_face_path'] = self.avatar_face_var.get()
            if hasattr(self, 'avatar_position_var'):
                self.settings['avatar_position'] = self.avatar_position_var.get()
            if hasattr(self, 'avatar_scale_var'):
                self.settings['avatar_scale'] = self.avatar_scale_var.get()
            if hasattr(self, 'avatar_standalone_var'):
                self.settings['avatar_standalone'] = self.avatar_standalone_var.get()

            _save_settings_atomic(self.settings)

            # DEBUG: Log custom blur regions state
            custom_regions = self.settings.get('custom_blur_regions', [])
            if custom_regions:
                print(f"[SAVE DEBUG] Saved {len(custom_regions)} custom blur regions:")
                for i, r in enumerate(custom_regions):
                    if isinstance(r, dict):
                        print(f"  Region {i}: enabled={r.get('enabled', False)}, text='{r.get('text', '')[:30]}'")

            logger.info("Settings saved successfully")
            if show_popup:
                messagebox.showinfo("Success", "Settings saved successfully!")
        except Exception as e:
            logger.error(f"Error saving settings: {e}")
            if show_popup:
                messagebox.showerror("Error", f"Failed to save settings: {str(e)}")

    def save_paths(self):
        """Save processing paths to JSON file"""
        try:
            paths = {
                'video_folder': self.video_folder_var.get(),
                'quotes_file': self.quotes_file_var.get(),
                'output_folder': self.output_folder_var.get()
            }
            with open('processing_paths.json', 'w', encoding='utf-8') as f:
                json.dump(paths, f, indent=2)
            logger.info("Paths saved successfully")
        except Exception as e:
            logger.error(f"Error saving paths: {e}")

