    def create_captions_tab(self):
        """Create Captions tab with left/right split — left controls, right live preview"""
        tab = tk.Frame(self.notebook, bg=AppStyles.BG_CARD)
        self.notebook.add(tab, text='💬 Captions')

        # ─── Horizontal split: left = scrollable controls, right = live preview ───
        hsplit = tk.PanedWindow(tab, orient='horizontal',
                                sashrelief='raised', sashwidth=4,
                                bg=AppStyles.BG_CARD, borderwidth=0)
        hsplit.pack(fill='both', expand=True)

        # ─── LEFT: scrollable controls ───────────────────────────────────
        left_holder = tk.Frame(hsplit, bg=AppStyles.BG_CARD)
        hsplit.add(left_holder, minsize=620, stretch='always')

        canvas = tk.Canvas(left_holder, bg=AppStyles.BG_CARD, highlightthickness=0)
        scrollbar = ttk.Scrollbar(left_holder, orient='vertical', command=canvas.yview)
        content = tk.Frame(canvas, bg=AppStyles.BG_CARD)

        content.bind('<Configure>', lambda e: canvas.configure(scrollregion=canvas.bbox('all')))
        canvas.create_window((0, 0), window=content, anchor='nw')
        canvas.configure(yscrollcommand=scrollbar.set)

        canvas.pack(side='left', fill='both', expand=True, padx=4, pady=4)
        scrollbar.pack(side='right', fill='y')

        # Enable mouse wheel scrolling
        self.setup_mousewheel_scroll(canvas, content)

        # ─── RIGHT: live preview ──────────────────────────────────────────
        right_pane = tk.Frame(hsplit, bg=AppStyles.BG_CARD)
        hsplit.add(right_pane, minsize=300, stretch='never')

        prev_card = tk.LabelFrame(right_pane, text='👁 Live Preview',
                                  bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                                  font=('Segoe UI', 9, 'bold'),
                                  labelanchor='nw', bd=1,
                                  relief='solid',
                                  highlightbackground=AppStyles.BORDER_LIGHT)
        prev_card.pack(fill='both', expand=True, padx=4, pady=4)

        prev_inner = tk.Frame(prev_card, bg=AppStyles.BG_CARD)
        prev_inner.pack(fill='both', expand=True, padx=6, pady=4)

        # Phone-aspect canvas (9:16, ~180×320)
        prev_holder = tk.Frame(prev_inner, bg='#0a0a0a',
                               highlightbackground=AppStyles.BORDER_LIGHT,
                               highlightthickness=1)
        prev_holder.pack(padx=4, pady=4)
        self.caption_preview_canvas = tk.Canvas(prev_holder, width=180, height=320,
                                                bg='#000000', highlightthickness=0)
        self.caption_preview_canvas.pack()

        tk.Label(prev_inner, text='Auto-updates when you change settings below',
                bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_MEDIUM,
                font=('Segoe UI', 7, 'italic')).pack(pady=(0, 2))

        # Initialize preview
        self.update_caption_preview()

        # ═══════════════════════════════════════════════════════════
