    def _inline_duration(self, parent, setting_key, default, lo=0.1, hi=10.0, length=110):
        """Compact horizontal duration slider with showvalue."""
        var = tk.DoubleVar(value=self.settings.get(setting_key, default))
        setattr(self, f'_{setting_key}_inline_var', var)
        scale = tk.Scale(parent, from_=lo, to=hi, resolution=0.1,
                         orient='horizontal', variable=var, length=length,
                         bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                         highlightthickness=0, troughcolor=AppStyles.BG_CARD,
                         font=('Segoe UI', 9), showvalue=True,
                         command=lambda v, k=setting_key: self.update_setting(k, float(v)))
        return scale

    def _inline_label(self, parent, text):
        return tk.Label(parent, text=text, bg=AppStyles.BG_INPUT,
                        fg=AppStyles.TEXT_DARK, font=('Segoe UI', 10))

    def _inline_combobox(self, parent, setting_key, choices, default, width=8):
        var = tk.StringVar(value=self.settings.get(setting_key, default))
        setattr(self, f'_{setting_key}_inline_var', var)
        cb = ttk.Combobox(parent, textvariable=var, values=choices,
                          state='readonly', width=width)
        cb.bind('<<ComboboxSelected>>',
                lambda e, k=setting_key, v=var: self.update_setting(k, v.get()))
        return cb

    def create_transitions_tab(self):
        """Unified Transitions tab with scrollable content. Per-transition settings
        live inside each grid card so nothing is hidden below the fold."""
        tab = tk.Frame(self.notebook, bg=AppStyles.BG_CARD)
        self.notebook.add(tab, text='🎬 Transitions')

        canvas = tk.Canvas(tab, bg=AppStyles.BG_CARD, highlightthickness=0)
        scrollbar = ttk.Scrollbar(tab, orient='vertical', command=canvas.yview)
        outer = tk.Frame(canvas, bg=AppStyles.BG_CARD)
        outer.bind('<Configure>',
                   lambda e: canvas.configure(scrollregion=canvas.bbox('all')))
        canvas_window = canvas.create_window((0, 0), window=outer, anchor='nw')
        canvas.configure(yscrollcommand=scrollbar.set)
        canvas.pack(side='left', fill='both', expand=True, padx=6, pady=6)
        scrollbar.pack(side='right', fill='y')
        self.setup_mousewheel_scroll(canvas, outer)
        # Make the inner frame fill the canvas width
        def _on_canvas_resize(event):
            canvas.itemconfig(canvas_window, width=event.width)
        canvas.bind('<Configure>', _on_canvas_resize)

        # ---------------------------------------------------------------
        # 1) Unified transitions card — bigger tiles with toggle + SFX + duration
        # ---------------------------------------------------------------
        unified_card = self.create_modern_card(outer, "🎬 Transitions & Cinematic Effects")
        grid_container = tk.Frame(unified_card, bg=AppStyles.BG_CARD)
        grid_container.pack(fill='x', padx=15, pady=12)

        # Available SFX choices (must match AVAILABLE_SFX_CHOICES in script)
        # Scan the SFX library directory for user-added .wav/.mp3/.ogg files and
        # include them so custom files (e.g. shutter-click.wav) appear in the dropdown.
        sfx_choices = [
            '(default)', 'whoosh', 'swoosh', 'boom', 'glitch', 'chime', 'click',
            'zap', 'sparkle', 'hiss', 'rumble', 'shimmer', 'cinematic_whoosh',
            'bass_drop', 'riser', 'impact', 'vinyl_brake', 'notification',
            'sub_boom', 'horn_stab', '(none)'
        ]
        try:
            sfx_lib_path = Path(self.sfx_library_path_var.get())
            if sfx_lib_path.exists():
                for f in sorted(sfx_lib_path.iterdir()):
                    if f.suffix.lower() in ('.wav', '.mp3', '.ogg') and f.stem and f.stem not in sfx_choices:
                        sfx_choices.append(f.stem)
        except Exception:
            pass
        # Store so _reload_sfx_library can update combobox widgets
        self._sfx_choices = sfx_choices

        # Per-transition: (key, label, sfx_suffix, duration_key, duration_default, extra_type)
        # extra_type:
        #   None                  — no extra per-row widget
        #   'slide_dir'           — direction dropdown
        #   'wipe_dir'            — direction dropdown
        #   'bars_height'         — small height slider
        #   'lens_intensity'      — small intensity slider
        #   'light_leak_color'    — color palette dropdown
        #   'film_burn_dur'       — duration slider
        all_transitions = [
            ('transition_fade_in',        '🌅 Fade In',         'fade_in',
             'transition_fade_in_duration',  0.5, None),
            ('transition_fade_out',       '🌇 Fade Out',        'fade_out',
             'transition_fade_out_duration', 0.5, None),
            ('transition_zoom_in',        '🔍 Zoom In',         'zoom_in',
             'transition_zoom_in_duration',  1.0, None),
            ('transition_zoom_out',       '🔎 Zoom Out',        'zoom_out',
             'transition_zoom_out_duration', 1.0, None),
            ('transition_blur_in',        '💨 Blur In',         'blur_in',
             'transition_blur_duration',     0.5, None),
            ('transition_blur_out',       '🌫️ Blur Out',        'blur_out',
             'transition_blur_duration',     0.5, None),
            ('transition_slide_in',       '⬅️ Slide In',        'slide_in',
             'transition_slide_duration',    0.8, 'slide_dir'),
            ('transition_slide_out',      '➡️ Slide Out',       'slide_out',
             'transition_slide_duration',    0.8, 'slide_dir'),
            ('transition_wipe_in',        '📱 Wipe In',         'wipe_in',
             'transition_wipe_duration',     0.8, 'wipe_dir'),
            ('transition_wipe_out',       '📲 Wipe Out',        'wipe_out',
             'transition_wipe_duration',     0.8, 'wipe_dir'),
            ('transition_glitch_start',   '📺 Glitch Start',    'glitch_start',
             'transition_glitch_duration',   0.5, None),
            ('transition_glitch_end',     '⚡ Glitch End',      'glitch_end',
             'transition_glitch_duration',   0.5, None),
            ('transition_cinematic_bars', '🎞️ Cinematic Bars',  'cinematic_bars',
             'transition_bars_duration',     0.8, 'bars_height'),
            ('lens_flare_enabled',        '✨ Lens Flare',      'lens_flare',
             'lens_flare_duration',          2.0, 'lens_intensity'),
            ('light_leak_enabled',        '💡 Light Leaks',     'light_leak',
             'light_leak_duration',          3.0, 'light_leak_color'),
            ('film_burn_enabled',         '🔥 Film Burn',       'film_burn',
             'film_burn_duration',           1.5, 'film_burn_dur'),
            ('transition_bounce',         '⛹️ Bounce',          'bounce',
             'transition_bounce_duration',   0.6, None),
            ('transition_mask',           '🎭 Mask Reveal',     'mask',
             'transition_mask_duration',     0.6, 'mask_dir'),
            ('transition_bounce_mask',    '🪃 Bounce+Mask',     'bounce_mask',
             'transition_bounce_mask_duration', 0.8, 'mask_dir'),
            ('transition_radial_wipe',    '🌀 Radial Wipe',        'radial_wipe',
             'transition_radial_wipe_duration', 1.0, 'radial_dir'),
            ('transition_color_dissolve', '🌈 Color Dissolve',     'color_dissolve',
             'transition_color_dissolve_duration', 0.8, 'dissolve_dir'),
            ('transition_split_wipe',     '🚪 Split Wipe',         'split_wipe',
             'transition_split_wipe_duration', 1.0, 'split_dir'),
            ('transition_luma_wipe',      '☀️ Luma Wipe',          'luma_wipe',
             'transition_luma_wipe_duration', 0.8, 'luma_dir'),
        ]

        columns = 4
        for idx, (key, label, sfx_suffix, dur_key, dur_def, extra) in enumerate(all_transitions):
            r = idx // columns
            c = idx % columns

            # Tile — bordered card with internal padding
            tile = tk.Frame(grid_container, bg=AppStyles.BG_INPUT,
                            highlightbackground=AppStyles.BORDER_LIGHT,
                            highlightthickness=1, padx=6, pady=4)
            tile.grid(row=r, column=c, padx=3, pady=3, sticky='nsew')

            # Top line: toggle + optional extra widget
            top = tk.Frame(tile, bg=AppStyles.BG_INPUT)
            top.pack(fill='x')
            var = tk.BooleanVar(value=self.settings.get(key, False))
            setattr(self, f'_trans_{key}_var', var)
            chk = tk.Checkbutton(top, text=label, variable=var,
                                 bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                                 font=('Segoe UI', 9, 'bold'),
                                 activebackground=AppStyles.BG_INPUT,
                                 selectcolor=AppStyles.BG_CARD,
                                 command=lambda k=key, v=var: (
                                     self.update_setting(k, v.get()),
                                     self._on_transition_toggle_changed(k, v.get())))
            chk.pack(side='left')

            if extra == 'slide_dir':
                tk.Label(top, text='Dir:', bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_MEDIUM,
                         font=('Segoe UI', 7)).pack(side='left', padx=(6, 1))
                self._inline_combobox(top, 'transition_slide_direction',
                                      ['left', 'right', 'up', 'down'], 'left', width=6).pack(side='left')
            elif extra == 'wipe_dir':
                tk.Label(top, text='Dir:', bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_MEDIUM,
                         font=('Segoe UI', 7)).pack(side='left', padx=(6, 1))
                self._inline_combobox(top, 'transition_wipe_direction',
                                      ['left', 'right', 'up', 'down'], 'right', width=6).pack(side='left')
            elif extra == 'mask_dir':
                tk.Label(top, text='Shape:', bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_MEDIUM,
                         font=('Segoe UI', 7)).pack(side='left', padx=(6, 1))
                self._inline_combobox(top, 'transition_mask_shape',
                                      ['circle', 'square', 'diamond', 'star'], 'circle', width=7).pack(side='left')
                tk.Label(top, text=' BG:', bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_MEDIUM,
                         font=('Segoe UI', 7)).pack(side='left', padx=(6, 1))
                _mc_var = tk.StringVar(value=self.settings.get('transition_mask_color', '#000000'))
                _mc_preview = tk.Frame(top, bg=_mc_var.get(), width=14, height=14,
                                       relief='solid', borderwidth=1)
                _mc_preview.pack(side='left', padx=(0, 2))
                ModernButton(top, text='🎨',
                            bg_color=AppStyles.ACCENT_INFO,
                            font=('Segoe UI', 7),
                            padx=3, pady=1,
                            command=lambda: self.pick_setting_color('transition_mask_color', _mc_var, _mc_preview)).pack(side='left')
                # Register for preset refresh
                if not hasattr(self, '_color_pickers'):
                    self._color_pickers = {}
                self._color_pickers['transition_mask_color'] = {'var': _mc_var, 'preview': _mc_preview}
            elif extra == 'bars_height':
                tk.Label(top, text='H:', bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_MEDIUM,
                         font=('Segoe UI', 7)).pack(side='left', padx=(6, 1))
                self._inline_duration(top, 'transition_bars_height', 10, lo=2, hi=25, length=50).pack(side='left')
            elif extra == 'lens_intensity':
                tk.Label(top, text='Int:', bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_MEDIUM,
                         font=('Segoe UI', 7)).pack(side='left', padx=(6, 1))
