    def _browse_sfx_library(self):
        """Open a folder picker for the SFX library."""
        try:
            from tkinter import filedialog
            folder = filedialog.askdirectory(
                title='Select SFX Library Folder',
                initialdir=self.sfx_library_path_var.get()
            )
            if folder:
                self.sfx_library_path_var.set(folder)
                self.update_setting('transition_sfx_library', folder)
        except Exception as e:
            print(f'[WARNING] SFX folder browse failed: {e}')

    def _reload_sfx_library(self):
        """Force reload the SFX library cache and update SFX dropdown choices."""
        try:
            import sys as _sys
            from pathlib import Path as _P
            sfx_path = _P(str(APP_DIR / 'VoiceModules' / 'TransitionSFX'))
            if str(sfx_path) not in _sys.path:
                _sys.path.insert(0, str(sfx_path))
            from transition_sfx import TransitionSFX  # noqa
            _sfx = TransitionSFX(library_dir=self.sfx_library_path_var.get())
            # Rescan the library directory for user files
            lib_dir = _P(self.sfx_library_path_var.get())
            user_files = [f.stem for f in lib_dir.glob('*')
                          if f.suffix.lower() in ('.wav', '.mp3', '.ogg') and f.stem] \
                if lib_dir.exists() else []
            count = len(user_files)
            msg = f'Loaded {count} user SFX file(s)' if count else 'No user files found - using generated SFX'
            print(f'[OK] SFX library: {msg}')
            if hasattr(self, 'log_text'):
                self.log_text.insert('end', f'[SFX] {msg}\n')
                self.log_text.see('end')
            # Rebuild the master sfx_choices list
            base_choices = [
                '(default)', 'whoosh', 'swoosh', 'boom', 'glitch', 'chime', 'click',
                'zap', 'sparkle', 'hiss', 'rumble', 'shimmer', 'cinematic_whoosh',
                'bass_drop', 'riser', 'impact', 'vinyl_brake', 'notification',
                'sub_boom', 'horn_stab', '(none)'
            ]
            for fn in sorted(user_files):
                if fn not in base_choices:
                    base_choices.append(fn)
            self._sfx_choices = base_choices
            # Update every transition SFX combobox widget
            sfx_suffixes = [
                'fade_in', 'fade_out', 'zoom_in', 'zoom_out', 'blur_in', 'blur_out',
                'slide_in', 'slide_out', 'wipe_in', 'wipe_out', 'glitch_start', 'glitch_end',
                'cinematic_bars', 'lens_flare', 'light_leak', 'film_burn',
                'bounce', 'mask', 'bounce_mask', 'radial_wipe', 'color_dissolve',
                'split_wipe', 'luma_wipe',
            ]
            for suffix in sfx_suffixes:
                combo = getattr(self, f'_trans_sfx_combo_{suffix}', None)
                if combo is not None:
                    try:
                        combo['values'] = base_choices
                    except Exception:
                        pass
            if hasattr(self, 'log_text'):
                self.log_text.insert('end', f'[SFX] Updated {len(sfx_suffixes)} dropdown(s)\n')
                self.log_text.see('end')
        except Exception as e:
            print(f'[WARNING] SFX reload failed: {e}')

    def _test_sfx(self):
        """Play a sample SFX for preview — prefer sfx_library files, fall back to samples."""
        try:
            from pathlib import Path as _P
            # 1) Check user's sfx_library for any audio files
            lib_path = _P(self.sfx_library_path_var.get()) if hasattr(self, 'sfx_library_path_var') \
                else _P(str(APP_DIR / 'VoiceModules' / 'TransitionSFX' / 'sfx_library'))
            if not lib_path.exists():
                lib_path = _P(str(APP_DIR / 'VoiceModules' / 'TransitionSFX' / 'sfx_library'))
            candidate = None
            if lib_path.is_dir():
                for ext in ('.wav', '.mp3', '.ogg', '.m4a'):
                    found = sorted(lib_path.glob(f'*{ext}'))
                    if found:
                        candidate = found[0]
                        break
            if candidate is not None and candidate.exists():
                if hasattr(self, 'log_text'):
                    self.log_text.insert('end', f'[SFX] Playing lib {candidate.name}...\n')
                    self.log_text.see('end')
                os.startfile(str(candidate))
                return
            # 2) Fallback: samples directory
            samples_path = _P(str(APP_DIR / 'VoiceModules' / 'TransitionSFX' / 'samples'))
            if not samples_path.exists():
                if hasattr(self, 'log_text'):
                    self.log_text.insert('end', '[SFX] No samples found. Generating...\n')
                    self.log_text.see('end')
                import soundfile as sf
                import transition_sfx
                sfx = transition_sfx.TransitionSFX()
                samples_path.mkdir(exist_ok=True)
                for n in ['whoosh', 'swoosh', 'boom', 'chime', 'click', 'zap', 'sparkle', 'hiss', 'rumble', 'shimmer']:
                    sf.write(str(samples_path / f'{n}.wav'), getattr(sfx, n)(0.5), sfx.sr)
            # Pick a random sample (not always whoosh)
            samples = sorted(samples_path.glob('*.wav'))
            if samples:
                import random as _r
                _r.seed()
                sample = samples[_r.randint(0, len(samples) - 1)]
                if hasattr(self, 'log_text'):
                    self.log_text.insert('end', f'[SFX] Playing {sample.name}...\n')
                    self.log_text.see('end')
                os.startfile(str(sample))
            else:
                if hasattr(self, 'log_text'):
                    self.log_text.insert('end', '[SFX] No audio files available.\n')
                    self.log_text.see('end')
        except Exception as e:
            print(f'[WARNING] SFX test failed: {e}')

    def _browse_custom_sfx(self):
        """Open a file picker for a single custom SFX audio file."""
        try:
            from tkinter import filedialog
            current = self.custom_sfx_file_var.get() or str(
                APP_DIR / 'VoiceModules' / 'TransitionSFX' / 'samples')
            initialdir = current if Path(current).exists() and Path(current).is_dir() \
                else str(Path(current).parent)
            path = filedialog.askopenfilename(
                title='Select Custom SFX File',
                initialdir=initialdir,
                filetypes=[('Audio files', '*.wav *.mp3 *.ogg *.m4a *.flac'),
                           ('All files', '*.*')]
            )
            if path:
                self.custom_sfx_file_var.set(path)
                self.update_setting('custom_sfx_file', path)
                if hasattr(self, 'log_text'):
                    self.log_text.insert('end', f'[CUSTOM-SFX] Selected: {Path(path).name}\n')
                    self.log_text.see('end')
        except Exception as e:
            print(f'[WARNING] Custom SFX browse failed: {e}')

    def _test_custom_sfx(self):
        """Play the user's custom SFX file in the default audio player."""
        try:
            from pathlib import Path as _P
            cf = self.custom_sfx_file_var.get()
            if not cf:
                if hasattr(self, 'log_text'):
                    self.log_text.insert('end', '[CUSTOM-SFX] No file selected.\n')
                    self.log_text.see('end')
                return
            p = _P(cf)
            if not p.exists():
                if hasattr(self, 'log_text'):
                    self.log_text.insert('end', f'[CUSTOM-SFX] File not found: {cf}\n')
                    self.log_text.see('end')
                return
            if hasattr(self, 'log_text'):
                self.log_text.insert('end', f'[CUSTOM-SFX] Playing {p.name}...\n')
                self.log_text.see('end')
            os.startfile(str(p))
        except Exception as e:
            print(f'[WARNING] Custom SFX test failed: {e}')

    # ----------------------------------------------------------------
    # Repeat-Selected Transitions: helpers
    # ----------------------------------------------------------------
    def _get_enabled_transition_keys(self):
        """Return a list of setting keys for every transition the user
        has currently enabled, in stable (original) order."""
        order = [
            'transition_fade_in', 'transition_fade_out',
            'transition_zoom_in', 'transition_zoom_out',
            'transition_blur_in', 'transition_blur_out',
            'transition_slide_in', 'transition_slide_out',
            'transition_wipe_in', 'transition_wipe_out',
            'transition_glitch_start', 'transition_glitch_end',
            'transition_cinematic_bars',
            'lens_flare_enabled', 'light_leak_enabled', 'film_burn_enabled',
            'transition_bounce', 'transition_mask', 'transition_bounce_mask',
            'transition_radial_wipe', 'transition_color_dissolve',
            'transition_split_wipe', 'transition_luma_wipe',
        ]
        return [k for k in order if self.settings.get(k, False)]

    def _refresh_repeat_selected_status(self):
        """Update the live 'N selected' status label next to the button."""
        enabled = self._get_enabled_transition_keys()
        n = len(enabled)
        if not hasattr(self, '_repeat_selected_status_var'):
            return
        if n == 0:
            self._repeat_selected_status_var.set('(0 enabled - tick some transitions above first)')
        elif n == 1:
            self._repeat_selected_status_var.set(f'({n} selected)')
        else:
            self._repeat_selected_status_var.set(f'({n} selected)')

    def _toggle_repeat_selected(self):
        """Flip the master enable flag and refresh the status label."""
        new_val = self._repeat_selected_enabled_var.get() if hasattr(self, '_repeat_selected_enabled_var') else False
        self.update_setting('transition_repeat_selected_enabled', new_val)
        # Refresh on every press: the user may have ticked new transitions
        self._refresh_repeat_selected_status()
        state = 'ENABLED' if new_val else 'disabled'
        n = len(self._get_enabled_transition_keys())
        mode = self.settings.get('transition_repeat_selected_mode', 'sequential')
        interval = self.settings.get('transition_repeat_selected_interval', 6.0)
        msg = (f'Repeat-Selected Transitions: {state} | '
               f'{n} transition(s) | mode={mode} | every {interval}s')
        print('[OK] ' + msg)
        if hasattr(self, 'log_text'):
            self.log_text.insert('end', '[TRANS] ' + msg + '\n')
            self.log_text.see('end')

    # Hook so any transition toggle updates the count label live
    def _on_transition_toggle_changed(self, key=None, value=None):
        """Callback used by every transition checkbox to keep the
        repeat-selected status label in sync."""
        self._refresh_repeat_selected_status()

    # Helper methods

    def setup_mousewheel_scroll(self, canvas, content):
        """Setup mouse wheel scrolling for a canvas (Windows compatible)"""
        def _on_mousewheel(event):
            # Windows mouse wheel
            canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

        def _bind_mousewheel(event):
            canvas.bind_all("<MouseWheel>", _on_mousewheel)

        def _unbind_mousewheel(event):
            canvas.unbind_all("<MouseWheel>")

        # Bind mouse wheel when mouse enters canvas/content
        canvas.bind('<Enter>', _bind_mousewheel)
        canvas.bind('<Leave>', _unbind_mousewheel)
        content.bind('<Enter>', _bind_mousewheel)
        content.bind('<Leave>', _unbind_mousewheel)

