        _lbs_i = self.cleanup_letterbox_bg_var.get()
        self._cleanup_lb_swatch = tk.Label(lb_r1, text='  ',
                                          bg=_lbs_i if _lbs_i.startswith('#') else '#000000',
                                          relief='solid', borderwidth=1)
        self._cleanup_lb_swatch.pack(side='left')
        def _on_lb_bg(*_a):
            v = self.cleanup_letterbox_bg_var.get().strip()
            if not v.startswith('#'):
                v = '#' + v
            # Normalize CSS shorthand (#RGB → #RRGGBB) and validate
            try:
                from PIL import ImageColor
                _rgb = ImageColor.getcolor(v, 'RGB')
                v = f'#{_rgb[0]:02X}{_rgb[1]:02X}{_rgb[2]:02X}'
            except Exception:
                pass  # leave as-is; _build_cleanup_command will default to black
            self.cleanup_letterbox_bg_var.set(v)
            try:
                self._cleanup_lb_swatch.config(bg=v)
            except Exception:
                pass
            self.update_setting('cleanup_letterbox_bg', v)
        self.cleanup_letterbox_bg_var.trace_add('write', _on_lb_bg)

        # ── Row 0 Col 2: COLOR WASH ──
