        self.cleanup_colorwash_color_var = tk.StringVar(
            value=self.settings.get('cleanup_colorwash_color', '#FFFFFF'))
        def _on_cw_preset(_e):
            k = cw_pc.get()
            if k in cw_preset_names:
                self.cleanup_colorwash_color_var.set(cw_preset_names[k])
                self.update_setting('cleanup_colorwash_color', cw_preset_names[k])
                self._cleanup_cw_swatch.config(bg=cw_preset_names[k])
            cw_pc.set('')
        cw_pc.bind('<<ComboboxSelected>>', _on_cw_preset)
