        self._cleanup_cw_swatch.pack(side='left')
        def _on_cw_hex(*_a):
            v = self.cleanup_colorwash_color_var.get().strip()
            if v in cw_preset_names:
                v = cw_preset_names[v]
            if not v.startswith('#'):
                v = '#' + v
            self.cleanup_colorwash_color_var.set(v.upper())
            try:
                self._cleanup_cw_swatch.config(bg=v.upper())
            except Exception:
                pass
            self.update_setting('cleanup_colorwash_color', v.upper())
        self.cleanup_colorwash_color_var.trace_add('write', _on_cw_hex)
