    # ----------------------------------------------------------------
    # EMBEDDED AM PREVIEW (lives inside the AM card on the right side)
    # ----------------------------------------------------------------
    def _build_embedded_am_preview(self, parent):
        """Build a compact Before/After preview panel that lives inside
        the AM card itself (no separate window). The user drags the
        AM sliders on the left and the After canvas updates live."""
        panel = tk.Frame(parent, bg=AppStyles.BG_CARD, bd=1, relief='solid')
        tk.Label(panel, text='👁 Live Preview (drag sliders → see here)',
                 bg=AppStyles.BG_CARD, fg=AppStyles.ACCENT_PRIMARY,
                 font=('Segoe UI', 9, 'bold')).pack(pady=(6, 4))

        # Source picker
        src_row = tk.Frame(panel, bg=AppStyles.BG_CARD)
        src_row.pack(fill='x', padx=4, pady=(0, 4))
        ModernButton(src_row, text='📁 Image…',
                    bg_color=AppStyles.ACCENT_SUCCESS,
                    font=('Segoe UI', 8), padx=6, pady=2,
                    command=self._am_preview_pick_image).pack(side='left', padx=2)
        ModernButton(src_row, text='🎲 Sample',
                    bg_color='#4a5568',
                    font=('Segoe UI', 8), padx=6, pady=2,
                    command=self._am_preview_use_sample).pack(side='left', padx=2)
        self._am_preview_source_label = tk.Label(
            src_row, text='Sample', bg=AppStyles.BG_CARD,
            fg=AppStyles.TEXT_MEDIUM, font=('Segoe UI', 8))
        self._am_preview_source_label.pack(side='left', padx=4)

        # Two side-by-side canvases: Before (left) and After (right)
        # so the user can see them next to each other and compare the
        # AM look at a glance.
        side_by_side = tk.Frame(panel, bg=AppStyles.BG_CARD)
        side_by_side.pack(fill='x', padx=4, pady=2)
        for label, attr in [('BEFORE', '_am_preview_canvas_before'),
                            ('AFTER', '_am_preview_canvas_after')]:
            sub = tk.Frame(side_by_side, bg=AppStyles.BG_CARD)
            sub.pack(side='left', fill='both', expand=True, padx=2)
            tk.Label(sub, text=label, bg=AppStyles.BG_CARD,
                     fg=AppStyles.TEXT_LIGHT, font=('Segoe UI', 8, 'bold')
                     ).pack()
            c = tk.Canvas(sub, width=150, height=320, bg='#000',
                          highlightthickness=1, highlightbackground='#333')
            c.pack(pady=(0, 2))
            setattr(self, attr, c)

        self._am_preview_status_var = tk.StringVar(value='Ready.')
        tk.Label(panel, textvariable=self._am_preview_status_var,
                 bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_MEDIUM,
                 font=('Segoe UI', 7), wraplength=180, justify='left'
                 ).pack(padx=4, pady=(2, 6), anchor='w')

        # State
        self._am_preview_source = None  # numpy HxWx3 uint8
        self._am_preview_image = None   # keep PhotoImage reference
        self._am_preview_render_id = None

        # Initial sample
        self._am_preview_use_sample()
        return panel

    def _am_preview_use_sample(self):
        """Build a small sample frame for the AM preview (gradient +
        text + bright blocks so blur/glow/edge effects are visible)."""
        try:
            import numpy as np
            from PIL import Image, ImageDraw, ImageFont
            h, w = 320, 180
            frame = np.zeros((h, w, 3), dtype=np.uint8)
            for y in range(h):
                for x in range(w):
                    t = (x + y) / (w + h)
                    frame[y, x, 0] = int(40 + 200 * t)
                    frame[y, x, 1] = int(180 - 120 * t)
                    frame[y, x, 2] = int(220 - 60 * t)
            frame[40:90, 20:80] = [245, 245, 245]
            frame[120:180, 70:140] = [255, 220, 100]
            frame[:4, :] = 0
            frame[-4:, :] = 0
            frame[:, :4] = 0
            frame[:, -4:] = 0
            pil = Image.fromarray(frame)
            draw = ImageDraw.Draw(pil)
            try:
                font = ImageFont.truetype('arialbd.ttf', 24)
            except Exception:
                try:
                    font = ImageFont.truetype('arial.ttf', 24)
                except Exception:
                    font = ImageFont.load_default()
            draw.text((45, 150), 'SAMPLE', fill=(20, 20, 20), font=font)
            self._am_preview_source = np.array(pil)
        except Exception as e:
            # Last-ditch: a flat color frame
            import numpy as np
            self._am_preview_source = np.full((320, 180, 3), 128, dtype=np.uint8)
        try:
            self._am_preview_source_label.config(text='Sample')
        except Exception:
            pass
        self._am_preview_render()

    def _am_preview_pick_image(self):
        from tkinter import filedialog
        path = filedialog.askopenfilename(
            title='Pick an image to preview against',
            filetypes=[('Image files', '*.png *.jpg *.jpeg *.bmp *.webp'),
                       ('All files', '*.*')])
        if not path:
            return
        try:
            from PIL import Image
            import numpy as np
            pil = Image.open(path).convert('RGB').resize((180, 320), Image.LANCZOS)
            self._am_preview_source = np.array(pil)
            self._am_preview_source_label.config(text=os.path.basename(path)[:24])
            self._am_preview_render()
        except Exception as e:
            try:
                messagebox.showerror('Image load failed', str(e))
            except Exception:
                pass

    def _am_preview_render(self):
        """Render the embedded AM preview. Re-draws BEFORE with the
        current source, and AFTER with the current AM template + all
        live slider values applied. Called automatically by
        update_setting whenever an AM key changes (debounced)."""
        if not hasattr(self, '_am_preview_canvas_before'):
            return
        if self._am_preview_source is None:
            return
        try:
            import numpy as np
            # BEFORE: just the source
            self._am_preview_draw(self._am_preview_canvas_before,
                                  self._am_preview_source)
            # AFTER: apply current AM look using current settings
            frame = self._am_preview_source.copy()
            am_template = self.am_template_var.get() if hasattr(self, 'am_template_var') else 'None'
            applied = []
            if am_template and am_template != 'None':
                try:
                    from youtube_video_automation_enhanced import VideoEffects
                    frame = VideoEffects.apply_alight_motion_look(frame, self.settings)
                    applied.append(f'AM:{am_template.split(" (")[0]}')
                except Exception as e:
                    applied.append(f'AM-error:{e}')
            self._am_preview_draw(self._am_preview_canvas_after, frame)
            self._am_preview_status_var.set(
                'Applied: ' + (' → '.join(applied) if applied else '(none — pick a template)'))
        except Exception as e:
            try:
                self._am_preview_status_var.set(f'Render error: {e}')
            except Exception:
                pass

    def _am_preview_draw(self, canvas, frame):
        """Draw a numpy HxWx3 frame onto a Tk canvas, scaling to fit
        while maintaining aspect ratio."""
        try:
            from PIL import Image, ImageTk
            pil = Image.fromarray(frame)
            cw = canvas.winfo_width() or 180
            ch = canvas.winfo_height() or 320
            fw, fh = pil.size
            scale = min(cw / fw, ch / fh)
            new_w = max(1, int(fw * scale))
            new_h = max(1, int(fh * scale))
            pil = pil.resize((new_w, new_h), Image.LANCZOS)
            self._am_preview_image = ImageTk.PhotoImage(pil)
            canvas.delete('all')
            canvas.create_image(cw // 2, ch // 2,
                                image=self._am_preview_image, anchor='center')
        except Exception:
            canvas.delete('all')

    def _am_preview_schedule_render(self):
        """Debounced (150ms) wrapper around _am_preview_render so we
        don't re-render 100x while a user drags a slider."""
        if self._am_preview_render_id is not None:
            try:
                self.root.after_cancel(self._am_preview_render_id)
            except Exception:
                pass
        try:
            self._am_preview_render_id = self.root.after(150, self._am_preview_render)
        except Exception:
            # If root isn't alive (headless test), just render now
            self._am_preview_render()

    def _on_am_dropdown_changed(self, dropdown):
        """Wrapper for the AM template dropdown's
        <<ComboboxSelected>>. Detects the special 'Apply Viral Reels
        Preset' sentinel and runs the preset apply, then snaps the
        dropdown back to the actual template that was just applied."""
        sel = self.am_template_var.get()
        if hasattr(self, '_am_preset_sentinel') and sel == self._am_preset_sentinel:
            # Inline the same logic as _apply_alight_motion_preset
            # but without the popup (the dropdown change is itself
            # the action — we don't need a confirmation dialog).
            template = 'Account Growth (Magenta+Green)'
            for spec in self._AM_TEMPLATE_CONTROLS.get(template, []):
                key = spec[0]
                default = spec[3]
                self.update_setting(key, default)
            self.am_template_var.set(template)
            self._on_am_template_changed()
            # Status hint (no popup, so it doesn't get in the way)
            try:
                self.status_var.set(
                    f'Viral Reels preset applied — {template} '
                    f'({len(self._AM_TEMPLATE_CONTROLS.get(template, []))} parameters restored to defaults).')
            except Exception:
                pass
            return
        # Normal selection — rebuild the slider grid for the new template
        self._on_am_template_changed()

    def _on_am_template_changed(self):
        """Rebuild the per-template main settings row when the user picks
        a different Alight Motion template."""
        from tkinter import ttk as _ttk
        self.update_setting('am_template', self.am_template_var.get())
        if hasattr(self, '_am_template_frame'):
            for w in self._am_template_frame.winfo_children():
                w.destroy()
        if hasattr(self, '_am_template_widgets'):
            self._am_template_widgets = {}
        template = self.am_template_var.get()
        if template == 'None' or template not in self._AM_TEMPLATE_CONTROLS:
            placeholder = tk.Label(self._am_template_frame,
                                  text='- No AM template applied -',
                                  bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_MEDIUM,
                                  font=('Segoe UI', 9, 'italic'))
            placeholder.pack(anchor='w', pady=4)
            return
        controls = self._AM_TEMPLATE_CONTROLS[template]
        # Header that shows the full XML effect list that is being controlled
        from PIL import ImageColor
        header = tk.Label(self._am_template_frame,
                          text=f'• {len(controls)} XML effect parameters exposed below',
                          bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_MEDIUM,
                          font=('Segoe UI', 8, 'italic'))
        header.pack(anchor='w', pady=(2, 4))
        grid = tk.Frame(self._am_template_frame, bg=AppStyles.BG_CARD)
        grid.pack(fill='x')
        for col in range(3):
            grid.columnconfigure(col, weight=1, uniform='am_ctrl')
        # 3 columns to fit the larger control surface
        for i, spec in enumerate(controls):
            # spec is (key, label, kind, default, *extras)
            key, label, kind = spec[0], spec[1], spec[2]
            default = spec[3]
            extras = spec[4:]
            r, c = divmod(i, 3)
            cell = tk.Frame(grid, bg=AppStyles.BG_INPUT, padx=6, pady=4)
            cell.grid(row=r, column=c, padx=3, pady=3, sticky='ew')
            tk.Label(cell, text=label + ':', bg=AppStyles.BG_INPUT,
                     fg=AppStyles.TEXT_DARK, font=('Segoe UI', 8),
                     wraplength=140, justify='left').pack(anchor='w')
            current = self.settings.get(key, default)
            # If the saved value is a zero-sentinel (0 / 0.0 / False /
            # empty string) but the table default is non-zero, the
            # saved value is almost certainly stale (e.g. leftover
            # from a previous "Reset" or fresh install where nothing
            # was ever written). Use the table default instead so the
            # user sees the actual template look when they pick a
            # template, not a blank canvas. If the user genuinely
            # wants 0, they can drag the slider back to 0 after.
            if current in (0, 0.0, False, '') and default not in (0, 0.0, False, ''):
                current = default
            if kind == 'slider':
                v = tk.DoubleVar(value=float(current))
                setattr(self, f'_am_{key}_var', v)
                # Adaptive range: must fit the default + headroom,
                # otherwise tk.Scale silently clamps. e.g. am_gain=1.29
                # would clamp to 1.0 with to=1.0. Use max(1.0, ...) so
                # values > 1 have room, and resolution=0.01 so values
                # like 0.12 don't snap to 0.10.
                try:
                    d = float(default)
                except Exception:
                    d = 1.0
                if d >= 0:
                    to_val = max(1.0, d * 1.5)
                else:
                    to_val = min(-1.0, d * 1.5)
                from_val = min(0.0, d * 1.5) if d < 0 else 0.0
                tk.Scale(cell, from_=from_val, to=to_val, resolution=0.01,
                         orient='horizontal', variable=v, length=110,
                         bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                         highlightthickness=0, troughcolor=AppStyles.BG_CARD,
                         showvalue=True,
                         command=lambda val, k=key, vv=v: self.update_setting(
                             k, float(val))).pack(fill='x', pady=(2, 0))
                self._am_template_widgets[key] = v
            elif kind == 'percent':
                v = tk.DoubleVar(value=float(current))
                setattr(self, f'_am_{key}_var', v)
                # percent: same adaptive-range logic as slider above
                try:
                    d = float(default)
                except Exception:
                    d = 1.0
                if d >= 0:
                    to_val = max(1.0, d * 1.5)
                else:
                    to_val = min(-1.0, d * 1.5)
                from_val = min(0.0, d * 1.5) if d < 0 else 0.0
                tk.Scale(cell, from_=from_val, to=to_val, resolution=0.01,
                         orient='horizontal', variable=v, length=110,
                         bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                         highlightthickness=0, troughcolor=AppStyles.BG_CARD,
                         showvalue=True,
                         command=lambda val, k=key, vv=v: self.update_setting(
                             k, float(val))).pack(fill='x', pady=(2, 0))
                self._am_template_widgets[key] = v
            elif kind == 'int_slider':
                # extras: (min, max)
                lo = extras[0] if len(extras) >= 1 else 0
                hi = extras[1] if len(extras) >= 2 else 10
                v = tk.IntVar(value=int(current))
                setattr(self, f'_am_{key}_var', v)
                tk.Scale(cell, from_=lo, to=hi, resolution=1,
                         orient='horizontal', variable=v, length=110,
                         bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                         highlightthickness=0, troughcolor=AppStyles.BG_CARD,
                         showvalue=True,
                         command=lambda val, k=key, vv=v: self.update_setting(
                             k, int(float(val)))).pack(fill='x', pady=(2, 0))
                self._am_template_widgets[key] = v
            elif kind == 'checkbox':
                v = tk.BooleanVar(value=bool(current))
                setattr(self, f'_am_{key}_var', v)
                tk.Checkbutton(cell, text='On', variable=v,
                               bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                               selectcolor=AppStyles.BG_CARD,
                               activebackground=AppStyles.BG_INPUT,
                               font=('Segoe UI', 9),
                               command=lambda k=key, vv=v: self.update_setting(
                                   k, vv.get())).pack(anchor='w')
                self._am_template_widgets[key] = v
            elif kind == 'options':
                # extras: [(label, value), ...]
                choices = extras[0] if extras else []
                v = tk.StringVar(value=str(current))
                setattr(self, f'_am_{key}_var', v)
                opt = tk.OptionMenu(cell, v, *[
                    lbl for lbl, _val in choices
                ])
                opt.config(bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                           font=('Segoe UI', 8), highlightthickness=0,
                           activebackground=AppStyles.BG_INPUT)
                opt['menu'].config(bg=AppStyles.BG_CARD,
                                   fg=AppStyles.TEXT_DARK,
                                   font=('Segoe UI', 8))
                opt.pack(fill='x', pady=(2, 0))
                def _on_options_change(*_a, k=key, vv=v, ch=choices):
                    label = vv.get()
                    value = next((val for lbl, val in ch if lbl == label),
                                  label)
                    self.update_setting(k, value)
                v.trace_add('write', _on_options_change)
                self._am_template_widgets[key] = v
            elif kind == 'int_options':
                # extras: [(label, value), ...]
                choices = extras[0] if extras else []
                v = tk.IntVar(value=int(current))
                setattr(self, f'_am_{key}_var', v)
                # Map current int value -> matching label
                try:
                    cur_label = next(lbl for lbl, val in choices
                                      if val == int(current))
                except StopIteration:
                    cur_label = choices[0][0] if choices else '0'
                opt = tk.OptionMenu(cell, v, *[
                    lbl for lbl, _val in choices
                ])
                opt.config(bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                           font=('Segoe UI', 8), highlightthickness=0,
                           activebackground=AppStyles.BG_INPUT)
                opt['menu'].config(bg=AppStyles.BG_CARD,
                                   fg=AppStyles.TEXT_DARK,
                                   font=('Segoe UI', 8))
                opt.pack(fill='x', pady=(2, 0))
                def _on_int_options_change(*_a, k=key, vv=v, ch=choices):
                    label_text = vv.get()
                    if isinstance(label_text, int):
                        # user picked a numeric label
                        self.update_setting(k, label_text)
                        return
                    try:
                        self.update_setting(k, int(label_text))
                    except Exception:
                        value = next((val for lbl, val in ch
                                      if lbl == label_text), 0)
                        self.update_setting(k, value)
                v.trace_add('write', _on_int_options_change)
                self._am_template_widgets[key] = v
            elif kind == 'color':
                v = tk.StringVar(value=current)
                setattr(self, f'_am_{key}_var', v)
                swatch = tk.Label(cell, text='      ', bg=current, relief='solid', borderwidth=1)
                entry = tk.Entry(cell, textvariable=v, width=10,
                                 bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                                 font=('Segoe UI', 9), relief='flat')
                entry.pack(side='bottom', fill='x', pady=(2, 0))
                swatch.pack(side='bottom', anchor='w', pady=(2, 0))
                def _on_color_change(*_a, k=key, vv=v, s=swatch):
                    try:
                        rgb = ImageColor.getcolor(vv.get(), 'RGB')
                        s.config(bg=vv.get())
                    except Exception:
                        s.config(bg='#808080')
                    self.update_setting(k, vv.get())
                v.trace_add('write', _on_color_change)
                self._am_template_widgets[key] = v

        # After building the slider widgets, persist the table
        # defaults back to self.settings for any control whose saved
        # value is the zero-sentinel. This is the durable fix for
        # the case where overlay_settings.json got overwritten with
        # 0.0 for every AM key (e.g. by an older Reset code path):
        # the user picks a template, the sliders immediately show
        # the real defaults, AND those defaults get written back to
        # disk so the next restart is also clean.
        seeded = 0
        for spec in controls:
            key = spec[0]
            default = spec[3]
            current = self.settings.get(key, default)
            if current in (0, 0.0, False, '') and default not in (0, 0.0, False, ''):
                self.settings[key] = default
                seeded += 1
        if seeded:
            try:
                self.save_settings(show_popup=False)
                logger.info(f"AM template '{template}': seeded {seeded} default values into settings")
            except Exception:
                pass

    def _build_am_filter_chain(self):
        """Backward-compat: read template from self.am_template_var."""
        return self._build_am_filter_chain_for_settings(self.settings)

    def _apply_alight_motion_preset(self):
        """Apply the Viral Reels (Account Growth) preset — push full
        XML-parameter defaults for every key in the template.

        Kept as a method for backward compatibility (anything that
        still calls it), but the actual user-facing trigger is now
        the special entry at the top of the template dropdown
        (handled in _on_am_dropdown_changed)."""
        template = 'Account Growth (Magenta+Green)'
        for spec in self._AM_TEMPLATE_CONTROLS.get(template, []):
            key = spec[0]
            default = spec[3]
            self.update_setting(key, default)
        if hasattr(self, 'am_template_var'):
            self.am_template_var.set(template)
        if hasattr(self, '_on_am_template_changed'):
            self._on_am_template_changed()

    def _reset_alight_motion_settings(self):
        """Reset all AM look-builder settings to neutral defaults
        (zeroed values, template = None)."""
        defaults = {'am_template': 'None'}
        for template_controls in self._AM_TEMPLATE_CONTROLS.values():
            for spec in template_controls:
                key = spec[0]
                kind = spec[2]
                default = spec[3]
                # Reset to a neutral value: 0 for sliders/percent/int_slider,
                # False for checkboxes, default for colors and options.
                if kind in ('slider', 'percent'):
                    defaults[key] = 0.0
                elif kind == 'int_slider':
                    defaults[key] = 0
                elif kind == 'checkbox':
                    defaults[key] = False
                elif kind in ('color', 'options'):
                    defaults[key] = default
                elif kind == 'int_options':
                    defaults[key] = 0
        for k, v in defaults.items():
            self.update_setting(k, v)
            var = getattr(self, f'_am_{k}_var', None)
            if var is not None:
                try:
                    var.set(v)
                except Exception:
                    pass
        if hasattr(self, 'am_template_var'):
            self.am_template_var.set('None')
        if hasattr(self, '_on_am_template_changed'):
            self._on_am_template_changed()
        messagebox.showinfo(
            'Reset',
            f'Alight Motion settings reset to neutral defaults.\n'
            f'({len(defaults) - 1} effect parameters reset.)')

    def create_modern_card(self, parent, title):
        """Create a modern card with shadow and rounded corners"""
        card_outer = tk.Frame(parent, bg=AppStyles.BORDER_LIGHT, pady=1, padx=1)
        card_outer.pack(fill='x', padx=8, pady=5)

        card = tk.Frame(card_outer, bg=AppStyles.BG_CARD, relief='flat')
        card.pack(fill='both', expand=True)

        header = tk.Frame(card, bg=AppStyles.BG_INPUT, height=30)
        header.pack(fill='x')
        header.pack_propagate(False)

        tk.Label(header, text=title,
                bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                font=('Segoe UI', 10, 'bold')).pack(anchor='w', padx=12, pady=4)

        return card

    def create_grid_card(self, parent, title, row, col, colspan=1, rowspan=1, sticky='nsew'):
        """Create a compact card in a grid layout"""
        card_outer = tk.Frame(parent, bg=AppStyles.BORDER_LIGHT, pady=1, padx=1)
        card_outer.grid(row=row, column=col, columnspan=colspan, rowspan=rowspan, padx=2, pady=2, sticky=sticky)

        card = tk.Frame(card_outer, bg=AppStyles.BG_CARD, relief='flat')
        card.pack(fill='both', expand=True)

        header = tk.Frame(card, bg=AppStyles.BG_INPUT, height=26)
        header.pack(fill='x')
        header.pack_propagate(False)

        tk.Label(header, text=title,
                bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                font=('Segoe UI', 8, 'bold')).pack(anchor='w', padx=6, pady=2)

        return card

    def create_path_field(self, parent, label_text, var, browse_cmd):
        """Create a path field with browse button"""
        field_container = tk.Frame(parent, bg=AppStyles.BG_CARD)
        field_container.pack(fill='x', padx=10, pady=5)

        tk.Label(field_container, text=label_text,
                bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_MEDIUM,
                font=('Segoe UI', 8)).pack(anchor='w', pady=(0, 3))

        path_row = tk.Frame(field_container, bg=AppStyles.BG_CARD)
        path_row.pack(fill='x')

        entry = tk.Entry(path_row, textvariable=var,
                        bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                        font=('Segoe UI', 8), relief='flat', width=20)
        entry.pack(side='left', fill='x', expand=True, padx=(0, 5))

        ModernButton(path_row, text='Browse',
                    bg_color=AppStyles.ACCENT_INFO,
                    font=('Segoe UI', 8, 'bold'),
                    padx=8, pady=2,
                    command=browse_cmd).pack(side='right')

    def create_modern_section(self, parent, title, fields):
        """Create a modern section with input fields"""
        card = self.create_modern_card(parent, title)

        for label_text, var, browse_cmd in fields:
            field_container = tk.Frame(card, bg=AppStyles.BG_CARD)
            field_container.pack(fill='x', padx=20, pady=12)

            tk.Label(field_container, text=label_text,
                    bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                    font=('Segoe UI', 10, 'bold')).pack(anchor='w', pady=(0, 5))

            input_frame = tk.Frame(field_container, bg=AppStyles.BG_CARD)
            input_frame.pack(fill='x')

            entry = tk.Entry(input_frame, textvariable=var,
                           bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                           font=('Segoe UI', 9), relief='flat', bd=2)
            entry.pack(side='left', fill='x', expand=True, ipady=6)

            btn_text = 'Browse Folder' if 'Folder' in label_text else 'Browse File'
            ModernButton(input_frame, text=btn_text,
                        bg_color=AppStyles.ACCENT_INFO,
                        font=('Segoe UI', 9, 'bold'),
                        padx=20, pady=8,
                        command=browse_cmd).pack(side='left', padx=(5, 0))

        return card

    def create_effect_section(self, parent, title, effects):
        """Create effect section with checkboxes"""
        card = self.create_modern_card(parent, title)

        for key, label in effects:
            var = tk.BooleanVar(value=self.settings.get(key, False))

            chk_frame = tk.Frame(card, bg=AppStyles.BG_CARD)
            chk_frame.pack(fill='x', padx=20, pady=6)

            chk = tk.Checkbutton(chk_frame, text=label,
                                variable=var, bg=AppStyles.BG_CARD,
                                fg=AppStyles.TEXT_DARK,
                                font=('Segoe UI', 10),
                                activebackground=AppStyles.BG_CARD,
                                selectcolor=AppStyles.BG_INPUT,
                                command=lambda k=key, v=var: self.update_setting(k, v.get()))
            chk.pack(anchor='w')

    def create_effect_grid(self, parent, title, effects, columns=4):
        """Create horizontal grid layout for effects (professional layout)"""
        card = self.create_modern_card(parent, title)

        grid_container = tk.Frame(card, bg=AppStyles.BG_CARD)
        grid_container.pack(fill='both', expand=True, padx=8, pady=6)

        for idx, (key, label) in enumerate(effects):
            row = idx // columns
            col = idx % columns

            var = tk.BooleanVar(value=self.settings.get(key, False))

            effect_cell = tk.Frame(grid_container, bg=AppStyles.BG_INPUT,
                                   highlightbackground=AppStyles.BORDER_LIGHT,
                                   highlightthickness=1,
                                   padx=8, pady=6)
            effect_cell.grid(row=row, column=col, padx=4, pady=4, sticky='ew')

            chk = tk.Checkbutton(effect_cell, text=label,
                                variable=var, bg=AppStyles.BG_INPUT,
                                fg=AppStyles.TEXT_DARK,
                                font=('Segoe UI', 8, 'bold'),
                                activebackground=AppStyles.BG_INPUT,
                                selectcolor=AppStyles.BG_CARD,
                                command=lambda k=key, v=var: self.update_setting(k, v.get()))
            chk.pack(anchor='w')

        for col in range(columns):
            grid_container.columnconfigure(col, weight=1, uniform='effect_col')

    def create_slider_control(self, parent, label, key, from_, to, default, resolution=1, value_format=None):
        """Create a modern slider control"""
        slider_frame = tk.Frame(parent, bg=AppStyles.BG_CARD)
        slider_frame.pack(fill='x', padx=10, pady=3)

        tk.Label(slider_frame, text=label,
                bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                font=('Segoe UI', 8)).pack(side='left')

        var = tk.DoubleVar(value=self.settings.get(key, default))

        if value_format:
            display_value = value_format(var.get())
        else:
            display_value = str(var.get())

        value_label = tk.Label(slider_frame, text=display_value,
                              bg=AppStyles.BG_CARD, fg=AppStyles.ACCENT_PRIMARY,
                              font=('Segoe UI', 8, 'bold'), width=5)
        value_label.pack(side='right')

        scale = tk.Scale(slider_frame, from_=from_, to=to, resolution=resolution,
                        orient='horizontal', variable=var,
                        bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                        highlightthickness=0, troughcolor=AppStyles.BG_INPUT,
                        showvalue=False, sliderlength=14, length=100,
                        command=lambda v, k=key, vl=value_label, fmt=value_format: self.on_slider_change(k, v, vl, fmt))
        scale.pack(side='left', fill='x', expand=True, padx=6)

        return scale

    def on_slider_change(self, key, value, value_label, value_format=None):
        """Handle slider value change"""
        val = float(value)

        # Format display value
        if value_format:
            display_value = value_format(val)
        else:
            display_value = f"{val:.2f}" if val < 10 else str(int(val))

        value_label.config(text=display_value)
        self.update_setting(key, val if val < 10 else int(val))

        # Trigger preview update for text settings
        for prefix in ['title', 'quote', 'cta']:
            if key.startswith(f'{prefix}_'):
                self.update_text_preview(prefix)
                return
        if key.startswith('caption_'):
            self.update_caption_preview()

    def create_text_controls(self, parent, prefix):
        """Create text controls for title/quote/cta"""

        # Live Preview Panel at the top
        preview_container = tk.Frame(parent, bg=AppStyles.BG_CARD)
        preview_container.pack(fill='x', padx=10, pady=(6, 3))

        tk.Label(preview_container, text='📺 Live Preview:',
                bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_MEDIUM,
                font=('Segoe UI', 7, 'bold')).pack(anchor='w')

        preview_frame = tk.Frame(preview_container, bg='#1a1a2e', relief='sunken', bd=1)
        preview_frame.pack(fill='x', pady=(2, 0))

        preview_canvas = tk.Canvas(preview_frame, height=40, bg='#1a1a2e', highlightthickness=0)
        preview_canvas.pack(fill='x', padx=3, pady=3)

        # Sample text for preview
        sample_texts = {'title': 'Sample Title', 'quote': '"Sample Quote"', 'cta': 'Follow Now!'}
        sample_text = sample_texts.get(prefix, 'Sample Text')

        # Create preview text item
        preview_text_id = preview_canvas.create_text(
            120, 25,
            text=sample_text,
            fill=self.settings.get(f'{prefix}_text_color', '#FFFFFF'),
            font=(self.settings.get(f'{prefix}_font_family', 'Arial'),
                  min(int(self.settings.get(f'{prefix}_font_size', 30)) // 2, 18),
                  'bold' if self.settings.get(f'{prefix}_font_bold', True) else 'normal')
        )

        # Store preview references for updates
        setattr(self, f'{prefix}_preview_canvas', preview_canvas)
        setattr(self, f'{prefix}_preview_text_id', preview_text_id)
        setattr(self, f'{prefix}_sample_text', sample_text)

        # Update preview when canvas is resized
        def on_canvas_resize(event):
            preview_canvas.coords(preview_text_id, event.width // 2, 25)
        preview_canvas.bind('<Configure>', on_canvas_resize)

        # Enable checkbox
        enabled_var = tk.BooleanVar(value=self.settings.get(f'{prefix}_enabled', True))
        tk.Checkbutton(parent, text=f'Enable {prefix.title()}',
                      variable=enabled_var, bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                      font=('Segoe UI', 8, 'bold'),
                      activebackground=AppStyles.BG_CARD,
                      selectcolor=AppStyles.BG_INPUT,
                      command=lambda: self.update_setting(f'{prefix}_enabled', enabled_var.get())).pack(anchor='w', padx=10, pady=4)

        # Font Size slider (increased max from 100 to 200 for larger text)
        default_sizes = {'title': 95, 'quote': 120, 'cta': 85}
        default_size = default_sizes.get(prefix, 30)
        self.create_slider_control(parent, 'Font Size:', f'{prefix}_font_size', 10, 200, default_size)

        # Font Family selection with system fonts
        font_frame = tk.Frame(parent, bg=AppStyles.BG_CARD)
        font_frame.pack(fill='x', padx=10, pady=4)

        tk.Label(font_frame, text='Font:',
                bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                font=('Segoe UI', 8)).pack(side='left')

        # Load system fonts from Windows fonts folder
        font_families = self.get_system_fonts(prefix)
        font_var = tk.StringVar(value=self.settings.get(f'{prefix}_font_family', 'Arial'))
        font_combo = ttk.Combobox(font_frame, textvariable=font_var, values=font_families,
                                  width=28, height=12)
        font_combo.pack(side='right', padx=5)

        def on_font_change(event, p=prefix, v=font_var):
            self.update_setting(f'{p}_font_family', v.get())
            self.update_text_preview(p)

        font_combo.bind('<<ComboboxSelected>>', on_font_change)

        # Store reference to combo for refresh
        setattr(self, f'{prefix}_font_combo', font_combo)

        # Custom fonts folder option
        custom_font_frame = tk.Frame(parent, bg=AppStyles.BG_CARD)
        custom_font_frame.pack(fill='x', padx=10, pady=2)

        tk.Label(custom_font_frame, text='Custom:',
                bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                font=('Segoe UI', 8)).pack(side='left')

        custom_font_var = tk.StringVar(value=self.settings.get(f'{prefix}_custom_fonts_folder', ''))
        custom_font_entry = tk.Entry(custom_font_frame, textvariable=custom_font_var,
                                     bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                                     font=('Segoe UI', 8), relief='flat', width=15)
        custom_font_entry.pack(side='left', padx=5)

        def browse_custom_fonts():
            folder = filedialog.askdirectory(title=f"Select Custom Fonts Folder for {prefix.title()}")
            if folder:
                custom_font_var.set(folder)
                self.update_setting(f'{prefix}_custom_fonts_folder', folder)
                # Refresh font list
                new_fonts = self.get_system_fonts(prefix)
                font_combo['values'] = new_fonts
                logger.info(f"Custom fonts folder for {prefix}: {folder}")

        ModernButton(custom_font_frame, text='📁',
                    bg_color=AppStyles.ACCENT_INFO,
                    font=('Segoe UI', 8, 'bold'),
                    padx=8, pady=4,
                    command=browse_custom_fonts).pack(side='left', padx=2)

        def clear_custom_fonts():
            custom_font_var.set('')
            self.update_setting(f'{prefix}_custom_fonts_folder', '')
            # Refresh with system fonts only
            new_fonts = self.get_system_fonts(prefix)
            font_combo['values'] = new_fonts

        ModernButton(custom_font_frame, text='✕',
                    bg_color=AppStyles.ACCENT_DANGER,
                    font=('Segoe UI', 8, 'bold'),
                    padx=6, pady=4,
                    command=clear_custom_fonts).pack(side='left', padx=2)

        # Font Style (Bold, Italic)
        style_frame = tk.Frame(parent, bg=AppStyles.BG_CARD)
        style_frame.pack(fill='x', padx=10, pady=3)

        tk.Label(style_frame, text='Style:',
                bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                font=('Segoe UI', 8)).pack(side='left')

        bold_var = tk.BooleanVar(value=self.settings.get(f'{prefix}_font_bold', True))

        def on_bold_change(p=prefix, v=bold_var):
            self.update_setting(f'{p}_font_bold', v.get())
            self.update_text_preview(p)

        tk.Checkbutton(style_frame, text='Bold',
                      variable=bold_var, bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                      font=('Segoe UI', 8),
                      activebackground=AppStyles.BG_CARD,
                      selectcolor=AppStyles.BG_INPUT,
                      command=on_bold_change).pack(side='left', padx=6)

        italic_var = tk.BooleanVar(value=self.settings.get(f'{prefix}_font_italic', False))

        def on_italic_change(p=prefix, v=italic_var):
            self.update_setting(f'{p}_font_italic', v.get())
            self.update_text_preview(p)

        tk.Checkbutton(style_frame, text='Italic',
                      variable=italic_var, bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                      font=('Segoe UI', 8),
                      activebackground=AppStyles.BG_CARD,
                      selectcolor=AppStyles.BG_INPUT,
                      command=on_italic_change).pack(side='left', padx=6)

        # Text Color picker
        color_frame = tk.Frame(parent, bg=AppStyles.BG_CARD)
        color_frame.pack(fill='x', padx=10, pady=3)

        tk.Label(color_frame, text='Text Color:',
                bg=AppStyles.BG_CARD, fg=AppStyles.TEXT_DARK,
                font=('Segoe UI', 8)).pack(side='left')

        color_var = tk.StringVar(value=self.settings.get(f'{prefix}_text_color', '#FFFFFF'))

        color_preview = tk.Frame(color_frame, bg=color_var.get(), width=24, height=18,
                                relief='solid', borderwidth=1)
        color_preview.pack(side='right', padx=3)

        tk.Entry(color_frame, textvariable=color_var, width=8,
                bg=AppStyles.BG_INPUT, fg=AppStyles.TEXT_DARK,
                font=('Segoe UI', 8), relief='flat').pack(side='right', padx=3)

        ModernButton(color_frame, text='🎨',
                    bg_color=AppStyles.ACCENT_INFO,
                    font=('Segoe UI', 8, 'bold'),
                    padx=6, pady=2,
                    command=lambda p=prefix, v=color_var, cp=color_preview: self.pick_color(p, v, cp)).pack(side='right', padx=3)

        # Background Color picker
        bg_color_frame = tk.Frame(parent, bg=AppStyles.BG_CARD)
