        def pick_outline_color():
            color = colorchooser.askcolor(title=f"Choose {prefix} outline color")
            if color[1]:
                outline_color_var.set(color[1])
                outline_preview.config(bg=color[1])
                self.update_setting(f'{prefix}_outline_color', color[1])
