    # ═══════════════════════════════════════════════════════════
    # STANDALONE SILENCE REMOVAL FUNCTIONS
    # ═══════════════════════════════════════════════════════════

    def _ss_browse_video(self):
        """Browse for a single video or audio file for standalone silence removal"""
        video = filedialog.askopenfilename(
            title='Select Video or Audio File',
            filetypes=[('Media Files', '*.mp4 *.avi *.mov *.mkv *.webm *.mp3 *.wav *.m4a *.flac *.aac *.ogg'),
                       ('Video Files', '*.mp4 *.avi *.mov *.mkv *.webm'),
                       ('Audio Files', '*.mp3 *.wav *.m4a *.flac *.aac *.ogg'),
                       ('All Files', '*.*')])
        if video:
            self.ss_video_var.set(video)
            # Show output path preview
            out = Path(video).parent / f"{Path(video).stem}_nosilence{Path(video).suffix}"
            self.ss_out_var.set(f'Output: {out}')
            self.ss_status_var.set('')
            logger.info(f'Standalone silence removal media selected: {video}')

    def _ss_browse_folder(self):
        """Browse for a folder to batch-process all media files"""
        folder = filedialog.askdirectory(title='Select Folder with Media Files')
        if folder:
            self.ss_video_var.set(folder)
            self.ss_out_var.set(f'Batch: {folder}')
            self.ss_status_var.set('')
            logger.info(f'Standalone silence removal folder selected: {folder}')

    def _ss_run(self):
        """Run silence removal on selected video or all videos in a folder"""
        path_str = self.ss_video_var.get().strip()
        if not path_str:
            messagebox.showerror('Error', 'Please select a video file or folder first')
            return

        path = Path(path_str)

        if path.is_dir():
            self._ss_run_folder(path)
        elif path.is_file():
            self._ss_run_file(path)
        else:
            messagebox.showerror('Error', f'Path not found: {path_str}')

    def _ss_run_file(self, video_path: Path):
        """Run silence removal on a single video file"""
        output_path = video_path.parent / f"{video_path.stem}_nosilence{video_path.suffix}"

        # Read checkbox states BEFORE spawning thread (tkinter vars are not thread-safe)
        crossfade_enabled = self.ss_crossfade_var.get()
        trans_enabled = self.ss_trans_var.get()

        trans_dur = 0.0
        use_tab = False
        if crossfade_enabled and trans_enabled:
            trans_dur = self.settings.get('silence_crossfade_duration', 0.3)
            use_tab = True
            logger.info(f"[SILENCE] Standalone — crossfade+click AND tab transitions, dur={trans_dur}")
        elif crossfade_enabled:
            trans_dur = self.settings.get('silence_crossfade_duration', 0.3)
            use_tab = False
            logger.info(f"[SILENCE] Standalone — crossfade+click only, dur={trans_dur}")
        elif trans_enabled:
            trans_dur = self.settings.get('silence_transition_duration', 0.3)
            use_tab = True
            logger.info(f"[SILENCE] Standalone — tab transitions only, dur={trans_dur}")
        else:
            logger.info(f"[SILENCE] Standalone — no transitions")

        # Disable button during processing
        self.ss_btn.config(state='disabled', text='Processing...')
        self.ss_status_var.set('Processing...')
        self.root.update()

        def _run():
            try:
                from youtube_video_automation_enhanced import remove_silence_from_video
                ffmpeg_exe = self._find_ffmpeg()
                ok = remove_silence_from_video(video_path, output_path,
                                               self.settings, ffmpeg_path=ffmpeg_exe,
                                               transition_duration=trans_dur,
                                               use_tab_transitions=use_tab)
                if ok and output_path.is_file():
                    self.ss_out_var.set(f'Done! Saved: {output_path}')
                    self.ss_status_var.set('Remove Silence')
                    messagebox.showinfo('Success',
                        f'Silence removed successfully!\\n\\n{output_path}')
                else:
                    self.ss_status_var.set('Remove Silence')
                    messagebox.showerror('Error', 'Silence removal failed. See console for details.')
            except Exception as e:
                logger.error(f'Standalone silence removal error: {e}', exc_info=True)
                self.ss_status_var.set('Error')
                messagebox.showerror('Error', f'Silence removal failed: {e}')
            finally:
                self.root.after(0, lambda: self.ss_btn.config(state='normal', text='Remove Silence'))

        import threading
        t = threading.Thread(target=_run, daemon=True)
        t.start()

    def _ss_run_folder(self, folder: Path):
        """Batch-process all videos and audio files in a folder"""
        media_exts = {'.mp4', '.avi', '.mov', '.mkv', '.webm',
                      '.mp3', '.wav', '.m4a', '.flac', '.aac', '.ogg'}
        videos = sorted([f for f in folder.iterdir() if f.suffix.lower() in media_exts and f.is_file()])

        if not videos:
            messagebox.showerror('Error', f'No media files found in: {folder}')
            return

        # Read checkbox state BEFORE spawning thread (tkinter vars are not thread-safe)
        crossfade_enabled = self.ss_crossfade_var.get()
        trans_enabled = self.ss_trans_var.get()

        trans_dur = 0.0
        use_tab = False
        if crossfade_enabled and trans_enabled:
            trans_dur = self.settings.get('silence_crossfade_duration', 0.3)
            use_tab = True
            logger.info(f"[SILENCE] Batch — crossfade+click AND tab transitions, dur={trans_dur}")
        elif crossfade_enabled:
            trans_dur = self.settings.get('silence_crossfade_duration', 0.3)
            use_tab = False
            logger.info(f"[SILENCE] Batch — crossfade+click only, dur={trans_dur}")
        elif trans_enabled:
            trans_dur = self.settings.get('silence_transition_duration', 0.3)
            use_tab = True
            logger.info(f"[SILENCE] Batch — tab transitions only, dur={trans_dur}")
        else:
            logger.info(f"[SILENCE] Batch — no transitions")

        # Disable button during processing
        self.ss_btn.config(state='disabled', text='Processing...')
        self.ss_status_var.set(f'Processing 0/{len(videos)}...')
        self.root.update()

        def _run():
            success_count = 0
            try:
                from youtube_video_automation_enhanced import remove_silence_from_video
                ffmpeg_exe = self._find_ffmpeg()

                for i, video_path in enumerate(videos):
                    self.ss_status_var.set(f'Processing {i+1}/{len(videos)}: {video_path.name}')
                    self.root.update()

                    output_path = folder / f"{video_path.stem}_nosilence{video_path.suffix}"
                    ok = remove_silence_from_video(video_path, output_path,
                                                   self.settings, ffmpeg_path=ffmpeg_exe,
                                                   transition_duration=trans_dur,
                                                   use_tab_transitions=use_tab)
                    if ok and output_path.is_file():
                        success_count += 1

                self.ss_out_var.set(f'Done! {success_count}/{len(videos)} processed in: {folder}')
                self.ss_status_var.set('Remove Silence')
                messagebox.showinfo('Batch Complete',
                    f'Processed {success_count}/{len(videos)} videos\\n\\nFolder: {folder}')
            except Exception as e:
                logger.error(f'Batch silence removal error: {e}', exc_info=True)
                self.ss_status_var.set('Error')
                messagebox.showerror('Error', f'Batch processing failed: {e}')
            finally:
                self.root.after(0, lambda: self.ss_btn.config(state='normal', text='Remove Silence'))

        import threading
        t = threading.Thread(target=_run, daemon=True)
        t.start()

    # STANDALONE VOICEOVER GENERATION FUNCTIONS
    # ═══════════════════════════════════════════════════════════

    def browse_standalone_file(self):
        """Browse for a single text file for standalone voiceover"""
        file = filedialog.askopenfilename(title="Select Text File",
                                         filetypes=[("Text Files", "*.txt"), ("All Files", "*.*")])
