    # ═══════════════════════════════════════════════════════════
    # NEUTTS HANDLER METHODS
    # ═══════════════════════════════════════════════════════════

    def check_neutts_connection(self):
        """Check if NeuTTS server is running and update status"""
        if NeuTTSHelper is None:
            self.neutts_status_label.config(
                text='❌ NeuTTS: Module Not Installed',
                fg=AppStyles.ACCENT_DANGER
            )
            return

        def check_in_thread():
            try:
                server_url = self.neutts_url_var.get()
                helper = NeuTTSHelper(server_url)
                is_running, status_msg = helper.check_server_status()

                # Update UI in main thread
                self.root.after(0, lambda: self._update_neutts_status(is_running, status_msg, helper))
            except Exception as e:
                self.root.after(0, lambda: self.neutts_status_label.config(
                    text=f'❌ Error: {str(e)}',
                    fg=AppStyles.ACCENT_DANGER
                ))

        # Run in background thread
        thread = threading.Thread(target=check_in_thread, daemon=True)
        thread.start()

    def _update_neutts_status(self, is_running, status_msg, helper):
        """Update NeuTTS status label and load voices if connected"""
        if is_running:
            self.neutts_status_label.config(
                text=status_msg,
                fg=AppStyles.ACCENT_SUCCESS
            )
            # Store helper for later use
            self._neutts_helper = helper
            # Load saved voice library
            helper.load_voice_library()
            self._populate_neutts_voices(helper)
        else:
            self.neutts_status_label.config(
                text=status_msg,
                fg=AppStyles.ACCENT_WARNING
            )
            # Fall back to local file if server offline
            self._auto_load_neutts_voices()

    def _populate_neutts_voices(self, helper):
        """Populate the cloned voices dropdown"""
        voices = helper.get_available_voices()
        voice_names = list(voices.keys())
        self.neutts_voice_combo['values'] = voice_names

        # Guard: ensure neutts_voice_var is a proper StringVar (not a str)
        if not isinstance(getattr(self, 'neutts_voice_var', None), tk.StringVar):
            self.neutts_voice_var = tk.StringVar(value=self.settings.get('neutts_voice', ''))

        # Select previously saved voice if available
        saved_voice = self.settings.get('neutts_voice', '')
        if saved_voice in voice_names:
            self.neutts_voice_var.set(saved_voice)
            self.update_setting('neutts_voice', saved_voice)
        elif voice_names:
            self.neutts_voice_var.set(voice_names[0])
            # Save the auto-selected voice
            self.update_setting('neutts_voice', voice_names[0])

    def browse_neutts_audio(self):
        """Browse for audio sample file for voice cloning"""
        filetypes = [
            ('Audio Files', '*.wav *.mp3 *.flac *.m4a'),
            ('WAV Files', '*.wav'),
            ('MP3 Files', '*.mp3'),
            ('All Files', '*.*')
        ]
        filename = filedialog.askopenfilename(
            title='Select Voice Sample Audio',
            filetypes=filetypes
        )
        if filename:
            self.neutts_audio_var.set(filename)

    def clone_neutts_voice(self):
        """Clone a voice from the provided audio sample"""
        if NeuTTSHelper is None:
            messagebox.showerror("Error", "NeuTTS module is not installed")
            return

        # Get input values
        voice_name = self.neutts_voice_name_var.get().strip()
        audio_file = self.neutts_audio_var.get().strip()
        ref_text = self.neutts_ref_text.get('1.0', 'end').strip()

        # Validate inputs
        if not voice_name:
            messagebox.showerror("Error", "Please enter a voice name")
            return
        if not audio_file:
            messagebox.showerror("Error", "Please select an audio sample file")
            return
        if not os.path.exists(audio_file):
            messagebox.showerror("Error", f"Audio file not found: {audio_file}")
            return
        if not ref_text:
            messagebox.showerror("Error", "Please enter the reference text (what is said in the audio)")
            return

        # Show progress
        self.neutts_status_label.config(
            text='⏳ Cloning voice...',
            fg=AppStyles.ACCENT_WARNING
        )

        def clone_in_thread():
            try:
                server_url = self.neutts_url_var.get()
                helper = NeuTTSHelper(server_url)

                # Load existing library
                helper.load_voice_library()

                # Clone the voice
                success, message = helper.clone_voice(
                    voice_name=voice_name,
                    audio_file_path=audio_file,
                    reference_text=ref_text,
                    language='en'
                )

                if success:
                    # Save library
                    helper.save_voice_library()
                    self._neutts_helper = helper

                # Update UI in main thread
                self.root.after(0, lambda: self._handle_clone_result(success, message, helper))

            except Exception as e:
                self.root.after(0, lambda: messagebox.showerror("Clone Error", str(e)))
                self.root.after(0, lambda: self.neutts_status_label.config(
                    text='❌ Clone failed',
                    fg=AppStyles.ACCENT_DANGER
                ))

        # Run in background thread
        thread = threading.Thread(target=clone_in_thread, daemon=True)
        thread.start()

    def _handle_clone_result(self, success, message, helper):
        """Handle the result of voice cloning"""
        if success:
            self.neutts_status_label.config(
                text=message,
                fg=AppStyles.ACCENT_SUCCESS
            )
            messagebox.showinfo("Success", message)
            # Refresh voices list
            self._populate_neutts_voices(helper)
            # Clear input fields
            self.neutts_voice_name_var.set('')
            self.neutts_audio_var.set('')
            self.neutts_ref_text.delete('1.0', 'end')
        else:
            self.neutts_status_label.config(
                text=message,
                fg=AppStyles.ACCENT_DANGER
            )
            messagebox.showerror("Clone Failed", message)

    def refresh_neutts_voices(self):
        """Refresh the list of cloned voices from the server"""
        if NeuTTSHelper is None:
            messagebox.showerror("Error", "NeuTTS module is not installed")
            return

        try:
            server_url = self.neutts_url_var.get()
            helper = NeuTTSHelper(server_url)

            # Check connection first
            is_running, status_msg = helper.check_server_status()
            if not is_running:
                self.neutts_status_label.config(
                    text=status_msg,
                    fg=AppStyles.ACCENT_WARNING
                )
                # Fall back to local file if server is offline
                self._auto_load_neutts_voices()
                return

            # Load voice library
            success, msg = helper.load_voice_library()
            if success:
                self._neutts_helper = helper
                self._populate_neutts_voices(helper)
                self.neutts_status_label.config(
                    text=f'✓ Loaded {len(helper.get_available_voices())} voices',
                    fg=AppStyles.ACCENT_SUCCESS
                )
            else:
                self.neutts_status_label.config(
                    text='No saved voices found',
                    fg=AppStyles.TEXT_MEDIUM
                )
                self.neutts_voice_combo['values'] = []

        except Exception as e:
            messagebox.showerror("Error", f"Failed to refresh voices: {str(e)}")

    def _auto_load_neutts_voices(self):
        """Auto-load NeuTTS voices from local file without needing server."""
        try:
            filepath = "neutts_voices.json"
            if not Path(filepath).exists():
                return
            with open(filepath, 'r') as f:
                voices = json.load(f)
            if voices:
                voice_names = list(voices.keys())
                self.neutts_voice_combo['values'] = voice_names

                # Guard: ensure neutts_voice_var is a proper StringVar
                if not isinstance(getattr(self, 'neutts_voice_var', None), tk.StringVar):
                    self.neutts_voice_var = tk.StringVar(value=self.settings.get('neutts_voice', ''))

                saved_voice = self.settings.get('neutts_voice', '')
                if saved_voice in voice_names:
                    self.neutts_voice_var.set(saved_voice)
                else:
                    self.neutts_voice_var.set(voice_names[0])
                    self.update_setting('neutts_voice', voice_names[0])
                self.neutts_status_label.config(
                    text=f'✓ {len(voice_names)} cloned voice(s) available',
                    fg=AppStyles.ACCENT_SUCCESS
                )
        except Exception as e:
            logger.debug(f"NeuTTS auto-load voices skipped: {e}")

    # ── Qwen3-TTS helpers ────────────────────────────────────────────
    def refresh_qwen3_status(self):
        """Check Qwen3 model availability and populate dropdowns."""
        if qwen3_helper is None:
            self.qwen3_status_label.config(
                text='⚠️ Qwen3-TTS: Helper module not found (qwen3_helper.py missing)',
                fg=AppStyles.ACCENT_WARNING
            )
            return
        try:
            # Populate speaker dropdown
            available_speakers = qwen3_helper.get_available_speakers()
            self.qwen3_speaker_combo['values'] = available_speakers
            current_speaker = self.settings.get('qwen3_speaker', 'Ryan (English)')
            if current_speaker in available_speakers:
                self.qwen3_speaker_var.set(current_speaker)
            elif available_speakers:
                self.qwen3_speaker_var.set(available_speakers[0])

            # Populate language dropdown
            self.qwen3_language_combo['values'] = qwen3_helper.SUPPORTED_LANGUAGES
            current_lang = self.settings.get('qwen3_language', 'English')
            if current_lang in qwen3_helper.SUPPORTED_LANGUAGES:
                self.qwen3_language_var.set(current_lang)
            else:
                self.qwen3_language_var.set('English')

            # Restore instruct from settings
            self.qwen3_instruct_var.set(self.settings.get('qwen3_instruct', ''))

            # Probe Python availability for qwen_tts
            py_path = qwen3_helper.reprobe_python()
            py_short = py_path.split('\\')[-1] if '\\' in py_path else py_path
            if hasattr(self, 'qwen3_python_label'):
                self.qwen3_python_label.config(text=f'Python: {py_short}')

            # Check model availability
            if qwen3_helper.is_available():
                self.qwen3_status_label.config(
                    text='✅ Qwen3-TTS: Model files found & ready',
                    fg=AppStyles.ACCENT_SUCCESS
                )
            else:
                self.qwen3_status_label.config(
                    text='⚠️ Qwen3-TTS: Model files missing — place them in VoiceModules/Qwen3-TTS/models/CustomVoice/',
                    fg=AppStyles.ACCENT_WARNING
                )
        except ImportError:
            self.qwen3_status_label.config(
                text='⚠️ Qwen3-TTS: Helper not available (qwen3_helper.py missing)',
                fg=AppStyles.ACCENT_WARNING
            )
        except Exception as e:
            self.qwen3_status_label.config(
                text=f'❌ Qwen3-TTS: Error — {e}',
                fg=AppStyles.ACCENT_DANGER
            )

    def reprobe_qwen3_python(self):
        """Force-reprobe the Python executable for qwen_tts and update the label."""
        try:
            if qwen3_helper is None:
                return
            py_path = qwen3_helper.reprobe_python()
            py_short = py_path.split('\\')[-1] if '\\' in py_path else py_path
            if hasattr(self, 'qwen3_python_label'):
                self.qwen3_python_label.config(text=f'Python: {py_short}')
            self.qwen3_status_label.config(
                text=f'🔍 Qwen3: Python reprobed → {py_short}',
                fg=AppStyles.ACCENT_INFO
            )
        except Exception as e:
            if hasattr(self, 'qwen3_python_label'):
                self.qwen3_python_label.config(text='Python: reprobe failed')

    # ── Qwen3 Voice Cloning helpers ─────────────────────────────
    def _on_qwen3_cloning_toggle(self):
        """Show/hide voice cloning options and save setting."""
        use_it = self.qwen3_use_cloning_var.get()
        if use_it:
            self.qwen3_clone_opts.pack(fill='x', padx=(12, 0), pady=(0, 4))
        else:
            self.qwen3_clone_opts.pack_forget()
        self.update_setting('qwen3_use_cloning', use_it)

    def _browse_qwen3_ref_audio(self):
        """Browse for a reference audio file for voice cloning."""
        path = filedialog.askopenfilename(
            title='Select Reference Audio (10-30 seconds of speech)',
            filetypes=[('Audio files', '*.wav *.mp3 *.m4a *.flac *.ogg'), ('All files', '*.*')],
        )
        if path:
            self.qwen3_clone_ref_audio_var.set(path)
            self.update_setting('qwen3_clone_ref_audio', path)

    def _test_qwen3_voice_clone(self):
        """Test voice cloning with current settings."""
        if qwen3_helper is None:
            messagebox.showerror('Error', 'Qwen3-TTS helper not available')
            return

        ref_audio = self.qwen3_clone_ref_audio_var.get().strip()
        if not ref_audio or not Path(ref_audio).exists():
            messagebox.showerror('Error', 'Please select a valid reference audio file first')
            return

        if not qwen3_helper.is_base_available():
            messagebox.showerror('Error',
                'Base model files not found.\nPlace them in VoiceModules/Qwen3-TTS/models/Base/')
            return

        import tempfile as _tf
        test_text = self.tts_test_text_var.get().strip()
        if not test_text:
            test_text = 'This is a voice cloning test. The cloned voice should sound like the reference speaker.'

        preview_file = Path(_tf.gettempdir()) / 'tts_preview_qwen3_clone.wav'
        language = self.settings.get('qwen3_language', 'English')
        ref_text = self.qwen3_clone_ref_text_var.get().strip()
        speed = float(self.settings.get('qwen3_speed', 0.85))

        self.preview_status_label.config(text='🔄 Loading Qwen3 Base model for voice cloning (may take 15-20s)...')
        self.root.update()

        try:
            result = qwen3_helper.generate_voice_clone(
                text=test_text,
                output_path=preview_file,
                ref_audio=ref_audio,
                ref_text=ref_text,
                language=language,
                speed=speed,
            )

            if result and result.exists():
                base_name = Path(ref_audio).stem
                self.preview_status_label.config(
                    text=f'▶ Playing Qwen3 Clone (based on: {base_name})')
                try:
                    os.startfile(str(result))
                except Exception:
                    pass
            else:
                self.preview_status_label.config(text='❌ Qwen3 voice cloning failed — check logs')
        except Exception as e:
            self.preview_status_label.config(text=f'❌ Qwen3 clone error: {str(e)}')
            logger.error(f'Qwen3 clone preview error: {e}')

    # ── Piper TTS Helpers ──────────────────────────────────────────────

    def _refresh_piper_speakers(self):
        """Update the Style/Emotion dropdown based on selected voice."""
        try:
            import piper_tts_helper as _p
            voice = self.piper_voice_var.get()
            speakers = _p.get_voice_speakers(voice)
            if speakers:
                display_names = [s['label'] for s in speakers]
                self.piper_speaker_combo['values'] = display_names
                # Keep current selection if valid
                current = self.piper_speaker_var.get()
                if current not in display_names:
                    self.piper_speaker_var.set(display_names[0])
                    self.update_setting('piper_speaker', speakers[0]['name'])
                self.piper_speaker_combo.configure(state='readonly')
                self.piper_style_hint.configure(
                    text=f'🎭 {len(speakers)} styles available' if _p.is_emotional_voice(voice) else f'({len(speakers)} speakers)')
                self.piper_style_hint.pack(side='left', padx=3)
            else:
                self.piper_speaker_combo['values'] = []
                self.piper_speaker_var.set('')
                self.piper_speaker_combo.configure(state='disabled')
                self.piper_style_hint.configure(text='(single-speaker model)')
        except Exception as e:
            logger.error(f'Piper speaker refresh error: {e}')

    def refresh_piper_status(self):
        """Update Piper TTS status and voice list."""
        try:
            import piper_tts_helper as _p
            available = _p.is_available()
            if available:
                # Check available voices
                downloaded = _p.get_downloaded_voices()
                if downloaded:
                    self.piper_status_label.config(
                        text=f'✅ Piper TTS: Ready ({len(downloaded)} voice(s) downloaded)',
                        fg=AppStyles.ACCENT_SUCCESS)
                else:
                    self.piper_status_label.config(
                        text='⚠️ Piper TTS: Ready — no voices downloaded yet',
                        fg=AppStyles.ACCENT_WARNING)
                # Populate voice dropdown with only downloaded voices
                downloaded = _p.get_downloaded_voices()
                self.piper_voice_combo['values'] = downloaded if downloaded else ['(no voices downloaded)']
                # Refresh speakers/emotions for current voice
                self._refresh_piper_speakers()
            else:
                self.piper_status_label.config(
                    text='❌ Piper TTS: Not available (engine files missing)',
                    fg=AppStyles.ACCENT_DANGER)
        except Exception as e:
            self.piper_status_label.config(
                text=f'❌ Piper TTS: Error — {str(e)}',
                fg=AppStyles.ACCENT_DANGER)
            logger.error(f'Piper status error: {e}')

    def _test_piper_voice(self):
        """Test current Piper voice by generating a short clip."""
        try:
            import piper_tts_helper as _p
            if not _p.is_available():
                messagebox.showerror('Error', 'Piper TTS engine not available')
                return
            voice = self.piper_voice_var.get()
            if not _p.is_voice_available(voice):
                # Offer to download
                dl = messagebox.askyesno(
                    'Download Voice?',
                    f"Voice '{voice}' is not downloaded yet.\nDownload it now?")
                if dl:
                    self.piper_status_label.config(text=f'⬇ Downloading {voice}...')
                    self.update_idletasks()
                    ok = _p.download_voice(voice)
                    if not ok:
                        messagebox.showerror('Error', f'Failed to download {voice}')
                        return
                    self.piper_status_label.config(text=f'✅ Downloaded {voice}',
                                                   fg=AppStyles.ACCENT_SUCCESS)
                    self.update_idletasks()
                else:
                    return

            # Use text from the Voice Preview text widget
            test_text = self.preview_text_widget.get('1.0', 'end-1c').strip()
            if not test_text:
                test_text = 'This is a test of the Piper TTS voice. How does it sound?'
            test_path = os.path.join(os.path.dirname(__file__), '_piper_preview.wav')
            speed_val = float(self.piper_speed_var.get())

            # Resolve speaker emotion/style
            speaker_id = None
            import piper_tts_helper as _p
            speaker_name = self.piper_speaker_var.get().strip()
            if speaker_name:
                speakers = _p.get_voice_speakers(voice)
                for s in speakers:
                    if s['label'] == speaker_name:
                        speaker_id = s['id']
                        break

            result = _p.generate_speech(test_text, test_path, voice=voice,
                                        length_scale=1.0 / speed_val,
                                        noise_scale=float(self.piper_noise_var.get()),
                                        speaker_id=speaker_id)
            if result:
                os.startfile(test_path)
                self.piper_status_label.config(text=f'▶ Playing Piper ({voice})',
                                               fg=AppStyles.ACCENT_SUCCESS)
            else:
                messagebox.showerror('Error', 'Piper TTS generation failed')
        except Exception as e:
            messagebox.showerror('Error', f'Piper test failed: {e}')
            logger.error(f'Piper test error: {e}')

    def _open_piper_voice_manager(self):
        """Open a dialog to browse and download Piper voices."""
        try:
            import piper_tts_helper as _p
            if not _p.is_available():
                messagebox.showerror('Error', 'Piper TTS engine not available')
                return
            self._show_piper_voice_browser()
        except Exception as e:
            messagebox.showerror('Error', f'Could not open voice manager: {e}')
            logger.error(f'Piper voice manager error: {e}')

    def _show_piper_voice_browser(self):
        """Display a voice browser dialog for downloading voices."""
        import piper_tts_helper as _p
        dialog = tk.Toplevel(self.root)
        dialog.title('Piper Voice Manager')
        dialog.geometry('750x550')
        dialog.configure(bg=AppStyles.BG_DARK)
        dialog.transient(self.root)
        dialog.grab_set()

        header = tk.Frame(dialog, bg=AppStyles.BG_DARK)
        header.pack(fill='x', padx=10, pady=8)
        tk.Label(header, text='🔊 Piper Voice Manager',
                bg=AppStyles.BG_DARK, fg='white',
                font=('Segoe UI', 12, 'bold')).pack(anchor='w')
        tk.Label(header, text='Select a language on the left, then download voices on the right',
                bg=AppStyles.BG_DARK, fg='#aaaaaa',
                font=('Segoe UI', 9)).pack(anchor='w')

        # Split pane: language list (left) + voice list (right)
        main_frame = tk.Frame(dialog, bg=AppStyles.BG_DARK)
        main_frame.pack(fill='both', expand=True, padx=10, pady=4)

        # ── Left: Language list ──
        left_frame = tk.Frame(main_frame, bg=AppStyles.BG_DARK, width=220)
        left_frame.pack(side='left', fill='y', padx=(0, 6))
        left_frame.pack_propagate(False)

        tk.Label(left_frame, text='🌐 Languages',
                bg=AppStyles.BG_DARK, fg='white',
                font=('Segoe UI', 9, 'bold')).pack(anchor='w', pady=(0, 2))

        lang_listbox = tk.Listbox(left_frame, bg='#2d2d2d', fg='#cccccc',
                                   selectbackground=AppStyles.ACCENT_PRIMARY,
                                   selectforeground='white',
                                   font=('Segoe UI', 9), relief='flat',
                                   borderwidth=0, highlightthickness=0)
        lang_listbox.pack(fill='both', expand=True)

        lang_scroll = tk.Scrollbar(left_frame, orient='vertical', command=lang_listbox.yview)
        lang_scroll.pack(side='right', fill='y')
        lang_listbox.configure(yscrollcommand=lang_scroll.set)

        # ── Right: Voice list ──
        right_frame = tk.Frame(main_frame, bg=AppStyles.BG_DARK)
        right_frame.pack(side='left', fill='both', expand=True)

        self._piper_lang_header = tk.Label(right_frame, text='← Select a language',
                                           bg=AppStyles.BG_DARK, fg='#888888',
                                           font=('Segoe UI', 9))
        self._piper_lang_header.pack(anchor='w', pady=(0, 4))

        voice_canvas = tk.Canvas(right_frame, bg='#2d2d2d', highlightthickness=0)
        voice_scroll = tk.Scrollbar(right_frame, orient='vertical', command=voice_canvas.yview)
        self._piper_voice_container = tk.Frame(voice_canvas, bg='#2d2d2d')

        self._piper_voice_container.bind(
            '<Configure>',
            lambda e: voice_canvas.configure(scrollregion=voice_canvas.bbox('all')))
        voice_canvas.create_window((0, 0), window=self._piper_voice_container, anchor='nw', width=480)
        voice_canvas.configure(yscrollcommand=voice_scroll.set)

        voice_canvas.pack(side='left', fill='both', expand=True)
        voice_scroll.pack(side='right', fill='y')

        # Populate languages
        languages = _p.get_languages()
        self._piper_lang_map = {}  # index -> lang dict

        for idx, lang in enumerate(languages):
            display = f"{lang['name']} ({lang['country']}) — {lang['voice_count']} voices"
            lang_listbox.insert(tk.END, display)
            self._piper_lang_map[idx] = lang

        def on_lang_select(event):
            selection = lang_listbox.curselection()
            if not selection:
                return
            idx = selection[0]
            lang = self._piper_lang_map.get(idx)
            if not lang:
                return
            self._piper_lang_header.config(
                text=f"📍 {lang['name']} ({lang['country']}) — {lang['voice_count']} voices available")
            # Clear old voice entries
            for w in self._piper_voice_container.winfo_children():
                w.destroy()
            # Populate voices
            voices = _p.get_voices_for_language(lang['code'])
            for v in voices:
                vf = tk.Frame(self._piper_voice_container, bg='#2d2d2d')
                vf.pack(fill='x', pady=3, padx=8)

                status = '✅' if v['downloaded'] else '⬇'
                quality_label = {'x_low': 'X-Low 20MB', 'low': 'Low 63MB',
                                 'medium': 'Medium 63MB', 'high': 'High 114MB'}.get(v['quality'], v['quality'])
                speakers = f" ({v['num_speakers']} spk)" if v['num_speakers'] > 1 else ''

                lbl = tk.Label(vf, text=f"{status} {v['name']} ({quality_label}){speakers}",
                               bg='#2d2d2d', fg='white' if v['downloaded'] else '#cccccc',
                               font=('Segoe UI', 9), anchor='w')
                lbl.pack(side='left', fill='x', expand=True)

                if not v['downloaded']:
                    dl_btn = ModernButton(vf, text='Download',
                        bg_color=AppStyles.ACCENT_PRIMARY, font=('Segoe UI', 8, 'bold'),
                        padx=8, pady=0,
                        command=lambda k=v['key']: self._piper_download_and_refresh(k, dialog))
                    dl_btn.pack(side='right', padx=(4, 0))

        lang_listbox.bind('<<ListboxSelect>>', on_lang_select)

        # Bottom status
        info_frame = tk.Frame(dialog, bg=AppStyles.BG_DARK)
        info_frame.pack(fill='x', padx=10, pady=6)
        self._piper_mgr_status = tk.Label(info_frame, text='',
                                          bg=AppStyles.BG_DARK, fg='#aaaaaa',
                                          font=('Segoe UI', 9))
        self._piper_mgr_status.pack(anchor='w')

        # Show first language by default
        if languages:
            lang_listbox.selection_set(0)
            lang_listbox.event_generate('<<ListboxSelect>>')

    def _piper_download_and_refresh(self, voice_key: str, dialog):
        """Download a Piper voice in a background thread so the UI doesn't freeze."""
        import piper_tts_helper as _p
        self._piper_mgr_status.config(text=f'⬇ Downloading {voice_key}... (may take a minute)')
        # Disable download buttons during download
        for child in self._piper_voice_container.winfo_children():
            for btn in child.winfo_children():
                if isinstance(btn, ModernButton):
                    btn.configure(state='disabled')

        def _do_download():
            try:
                ok = _p.download_voice(voice_key)
                dialog.after(0, lambda: self._piper_download_done(voice_key, dialog, ok))
            except Exception as e:
                dialog.after(0, lambda: self._piper_download_done(voice_key, dialog, False, str(e)))

        import threading
        t = threading.Thread(target=_do_download, daemon=True)
        t.start()

    def _piper_download_done(self, voice_key: str, dialog, success: bool, error: str = ''):
        """Callback after download finishes — runs on main thread."""
        if success:
            self._piper_mgr_status.config(text=f'✅ Downloaded {voice_key}!', fg=AppStyles.ACCENT_SUCCESS)
            self.refresh_piper_status()
            # Refresh the voice list in the dialog
            self._refresh_piper_voice_list(dialog)
        else:
            msg = error or 'Unknown error'
            self._piper_mgr_status.config(text=f'❌ Failed: {msg}', fg=AppStyles.ACCENT_DANGER)

    def _refresh_piper_voice_list(self, dialog):
        """Rebuild the voice entries in the manager to show updated download status."""
        import piper_tts_helper as _p
        # Find the currently selected language and re-render its voices
        # Simple approach: find the lang from the header text
        header_text = self._piper_lang_header.cget('text')
        for w in self._piper_voice_container.winfo_children():
            w.destroy()
        # Parse language code from header (format: "📍 English (United States) — 26 voices available")
        import re
        m = re.search(r'📍 (.+?) \((.+?)\) — (\d+) voices', header_text)
        if not m:
            return
        lang_name = m.group(1)
        country = m.group(2)
        # Find matching language
        languages = _p.get_languages()
        lang = None
        for l in languages:
            if l['name'] == lang_name and l['country'] == country:
                lang = l
                break
        if not lang:
            return
        voices = _p.get_voices_for_language(lang['code'])
        for v in voices:
            vf = tk.Frame(self._piper_voice_container, bg='#2d2d2d')
            vf.pack(fill='x', pady=3, padx=8)
            status = '✅' if v['downloaded'] else '⬇'
            quality_label = {'x_low': 'X-Low 20MB', 'low': 'Low 63MB',
                             'medium': 'Medium 63MB', 'high': 'High 114MB'}.get(v['quality'], v['quality'])
            speakers = f" ({v['num_speakers']} spk)" if v['num_speakers'] > 1 else ''
            lbl = tk.Label(vf, text=f"{status} {v['name']} ({quality_label}){speakers}",
                           bg='#2d2d2d', fg='white' if v['downloaded'] else '#cccccc',
                           font=('Segoe UI', 9), anchor='w')
            lbl.pack(side='left', fill='x', expand=True)
            if not v['downloaded']:
                dl_btn = ModernButton(vf, text='Download',
                    bg_color=AppStyles.ACCENT_PRIMARY, font=('Segoe UI', 8, 'bold'),
                    padx=8, pady=0,
                    command=lambda k=v['key']: self._piper_download_and_refresh(k, dialog))
                dl_btn.pack(side='right', padx=(4, 0))

    # ── Gemini API TTS helpers ───────────────────────────────────────────

    def _gc_refresh_status(self):
        """Update the status label — check auth method."""
        import os as _os
        key = self.gc_key_var.get().strip()
        sa = self.gc_sa_var.get().strip()
        mode = 'Cloud TTS' if getattr(self, 'gc_use_cloud_var', None) and self.gc_use_cloud_var.get() else 'Gemini TTS'
        if sa:
            sa_name = _os.path.basename(sa)
            self.gc_status_label.config(
                text=f'{mode} | Service Acct: {sa_name}',
                fg=AppStyles.ACCENT_SUCCESS)
        elif key:
            masked = key[:6] + '...' + key[-4:] if len(key) > 12 else key
            self.gc_status_label.config(
                text=f'{mode} | Key: {masked}',
                fg=AppStyles.ACCENT_SUCCESS)
        else:
            self.gc_status_label.config(
                text=f'{mode} | No API key or service account',
                fg=AppStyles.ACCENT_WARNING)

    def _gc_populate_keys(self):
        """Populate the API key dropdown from saved Gemini keys."""
        saved = getattr(self, '_saved_api_keys', [])
        masked = []
        for k in saved:
            if len(k) > 12:
                masked.append(k[:6] + '...' + k[-4:])
            else:
                masked.append(k[:8] + '...' if len(k) > 8 else k)
        self.gc_key_combo['values'] = masked + saved  # both display and raw
        # Pre-select if a key was previously saved
        prev_key = self.settings.get('gemini_api_key', '')
        if prev_key:
            self.gc_key_var.set(prev_key)
            # Also try to match in the combined list
            for val in self.gc_key_combo['values']:
                if val == prev_key:
                    self.gc_key_var.set(val)
                    break
        # When user selects, write the real key
        def _on_key_select(evt):
            display = self.gc_key_var.get()
            # If it's a masked key, find the real one from saved list
            if '...' in display:
                for real_key in saved:
                    masked_version = real_key[:6] + '...' + real_key[-4:] if len(real_key) > 12 else real_key[:8] + '...'
                    if masked_version == display:
                        self.gc_key_var.set(real_key)
                        break
            self.update_setting('gemini_api_key', self.gc_key_var.get())
            self._gc_refresh_status()
        self.gc_key_combo.bind('<<ComboboxSelected>>', _on_key_select)

    def _gc_test_voice(self):
        """Generate a short test phrase via Gemini API TTS / Cloud TTS and play it."""
        import tempfile, os, traceback
        from pathlib import Path
        use_cloud = self.gc_use_cloud_var.get()
        api_key = self.gc_key_var.get().strip()
        sa_path = self.gc_sa_var.get().strip()
        # Validate the right credential for the active mode.
        # The expressive Gemini voices route through the Cloud endpoint via a
        # service account, so an SA is sufficient even in Gemini mode.
        if use_cloud:
            if not sa_path:
                messagebox.showwarning('No Service Account',
                    'Cloud TTS needs a service account .json key.\nClick Browse next to "Service Acct" to select it.')
                return
        else:
            if not api_key and not sa_path:
                messagebox.showwarning('No Credential',
                    'Gemini TTS needs either a service account .json (recommended, for the\n'
                    'expressive star-named voices) or a Gemini API key.')
                return
        voice = self.gc_voice_var.get()
        style_prompt = getattr(self, 'gc_style_var', None)
        style_prompt = style_prompt.get().strip() if style_prompt is not None else ''
        test_text = 'Movies, oh my gosh, I just absolutely love them. They take you to entirely different worlds.'
        preview_file = Path(tempfile.gettempdir()) / 'tts_preview_gemini_api.wav'
        try:
            import gemini_api_tts_helper as _gtts
            success, details = _gtts.generate_speech(
                test_text,
                str(preview_file),
                {
                    'gemini_api_key': api_key,
                    'gemini_tts_voice': voice,
                    'gemini_tts_model': self.gc_model_var.get(),
                    'gemini_tts_speed': self.gc_speed_var.get(),
                    'service_account_path': sa_path,
                    'use_cloud_tts': use_cloud,
                    'cloud_tts_voice': voice,
                    'gemini_tts_prompt': style_prompt,
                    'gemini_tts_language': self.settings.get('gemini_tts_language', 'en-US'),
                }
            )
            if success:
                self._gc_play_audio(str(preview_file))
                mode_label = 'Cloud TTS' if use_cloud else self.gc_model_var.get()
                self.gc_status_label.config(
                    text=f'▶ Playing: {voice} ({mode_label})',
                    fg=AppStyles.ACCENT_SUCCESS)
            else:
                err_msg = details[0] if isinstance(details, list) and details else str(details)
                messagebox.showerror('Error', f'TTS failed:\n{err_msg}')
        except Exception as e:
            traceback.print_exc()
            messagebox.showerror('Error', f'TTS error: {e}')

    @staticmethod
    def _gc_play_audio(filepath):
        """Play an audio file using the default system player."""
        import os, platform
        if platform.system() == 'Windows':
            os.startfile(filepath)
        else:
            import subprocess
            try:
                subprocess.Popen(['xdg-open', filepath])
            except Exception:
                subprocess.Popen(['ffplay', '-nodisp', '-autoexit', filepath])

    def _gc_browse_sa(self):
        """Browse for a service account JSON key file."""
        from tkinter import filedialog
        fp = filedialog.askopenfilename(
            title='Select Service Account JSON Key',
            filetypes=[('JSON files', '*.json'), ('All files', '*.*')]
        )
        if fp:
            self.gc_sa_var.set(fp)
            self.update_setting('service_account_path', fp)
            self._gc_refresh_status()

    def _gc_clear_sa(self):
        """Clear the service account path."""
        self.gc_sa_var.set('')
        self.update_setting('service_account_path', '')
        self._gc_refresh_status()

    def _gc_on_voice_selected(self):
        """Save the picked voice to the correct setting key for the active mode."""
        voice = self.gc_voice_var.get()
        if self.gc_use_cloud_var.get():
            self.update_setting('cloud_tts_voice', voice)
        else:
            self.update_setting('gemini_tts_voice', voice)

    def _gc_toggle_tts_mode(self):
        """Toggle between Gemini TTS and Cloud TTS mode."""
        use_cloud = self.gc_use_cloud_var.get()
        self.update_setting('use_cloud_tts', use_cloud)
        # Swap voice lists, restoring each mode's saved voice
        import gemini_api_tts_helper as _gtts
        if use_cloud:
            voices = _gtts.get_voice_keys(cloud=True)
            saved = self.settings.get('cloud_tts_voice', voices[0] if voices else 'en-US-Studio-Q')
            if saved not in voices:
                saved = voices[0] if voices else 'en-US-Studio-Q'
            self.gc_voice_combo['values'] = voices
            self.gc_voice_var.set(saved)
            self.gc_status_label.config(
                text='Cloud TTS: requires service account (.json key file)')
        else:
            voices = _gtts.get_voice_keys(cloud=False)
            saved = self.settings.get('gemini_tts_voice', voices[0] if voices else 'Zephyr')
            if saved not in voices:
                saved = voices[0] if voices else 'Zephyr'
            self.gc_voice_combo['values'] = voices
            self.gc_voice_var.set(saved)
            self._gc_refresh_status()


